Certainly! Below is a **complete, working Rust implementation of an LRU (Least Recently Used) Cache** using `HashMap` and a doubly linked list. This implementation gives O(1) complexity for `get` and `put` operations.

The key ideas:
- **HashMap** for key-value lookup.
- **Doubly Linked List** for maintaining the usage order (most recently used at the front).
- Each node keeps its key and value, and the map points to node pointers.

**Working Example:**

```rust
use std::collections::HashMap;
use std::cell::{RefCell};
use std::rc::{Rc, Weak};

// Define a doubly-linked list Node
type Link<K, V> = Option<Rc<RefCell<Node<K, V>>>>;

struct Node<K, V> {
    key: K,
    value: V,
    prev: Option<Weak<RefCell<Node<K, V>>>>,
    next: Link<K, V>,
}

pub struct LRUCache<K: Eq + std::hash::Hash + Copy, V: Copy> {
    map: HashMap<K, Rc<RefCell<Node<K, V>>>>,
    capacity: usize,
    head: Link<K, V>, // Most recently used
    tail: Link<K, V>, // Least recently used
}

impl<K: Eq + std::hash::Hash + Copy, V: Copy> LRUCache<K, V> {
    pub fn new(capacity: usize) -> Self {
        LRUCache {
            map: HashMap::with_capacity(capacity),
            capacity,
            head: None,
            tail: None,
        }
    }

    pub fn get(&mut self, key: K) -> Option<V> {
        if let Some(node_rc) = self.map.get(&key) {
            let value = node_rc.borrow().value;
            self.move_to_head(Rc::clone(node_rc));
            Some(value)
        } else {
            None
        }
    }

    pub fn put(&mut self, key: K, value: V) {
        if let Some(node_rc) = self.map.get(&key) {
            node_rc.borrow_mut().value = value;
            self.move_to_head(Rc::clone(node_rc));
        } else {
            // New node
            let new_node = Rc::new(RefCell::new(Node {
                key,
                value,
                prev: None,
                next: None,
            }));

            // Attach at head
            self.attach_to_head(Rc::clone(&new_node));

            self.map.insert(key, Rc::clone(&new_node));

            if self.map.len() > self.capacity {
                self.pop_tail();
            }
        }
    }

    // Helper: moves a node to the head
    fn move_to_head(&mut self, node_rc: Rc<RefCell<Node<K, V>>>) {
        self.detach(node_rc.clone());
        self.attach_to_head(node_rc);
    }

    // Helper: attach a node to the head
    fn attach_to_head(&mut self, node_rc: Rc<RefCell<Node<K, V>>>) {
        node_rc.borrow_mut().next = self.head.clone();
        node_rc.borrow_mut().prev = None;

        if let Some(old_head) = &self.head {
            old_head.borrow_mut().prev = Some(Rc::downgrade(&node_rc));
        }
        self.head = Some(node_rc.clone());

        if self.tail.is_none() {
            self.tail = Some(node_rc);
        }
    }

    // Helper: detach a node from the list
    fn detach(&mut self, node_rc: Rc<RefCell<Node<K, V>>>) {
        let prev = node_rc.borrow().prev.clone();
        let next = node_rc.borrow().next.clone();

        if let Some(prev_weak) = prev {
            if let Some(prev_rc) = prev_weak.upgrade() {
                prev_rc.borrow_mut().next = next.clone();
            }
        } else {
            // node is head
            self.head = next.clone();
        }

        if let Some(next_rc) = next {
            next_rc.borrow_mut().prev = prev;
        } else {
            // node is tail
            self.tail = prev.and_then(|pr| pr.upgrade());
        }
    }

    // Helper: removes the least recently used node (tail)
    fn pop_tail(&mut self) {
        if let Some(tail_rc) = self.tail.clone() {
            let key = tail_rc.borrow().key;
            self.detach(Rc::clone(&tail_rc));
            self.map.remove(&key);
        }
    }
}

// Example main for testing
fn main() {
    let mut cache = LRUCache::new(2);

    cache.put(1, 1);
    cache.put(2, 2);
    assert_eq!(cache.get(1), Some(1)); // returns 1
    cache.put(3, 3);                   // evicts key 2
    assert_eq!(cache.get(2), None);    // returns None (not found)
    cache.put(4, 4);                   // evicts key 1
    assert_eq!(cache.get(1), None);    // returns None (not found)
    assert_eq!(cache.get(3), Some(3)); // returns 3
    assert_eq!(cache.get(4), Some(4)); // returns 4

    println!("All tests passed!");
}
```

---

### How it works

- `put(key, value)` inserts or updates a key.
- `get(key)` returns the value if present, marking the entry as most-recently-used.
- When `put` would exceed capacity, it evicts the least-recently-used (tail of the list).
- The doubly linked list lets us move nodes to the head in O(1), and all operations are O(1).

This code is **self-contained and will run as a single file**.  
If you want to use other types than `Copy` keys and values, additional work is needed for ownership and borrowing rules.

