Certainly! Here’s a simple **Trie** (prefix tree) implementation in Rust. This implementation supports insertion, exact search, and prefix search (starts_with).

```rust
use std::collections::HashMap;

#[derive(Debug, Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

#[derive(Debug, Default)]
pub struct Trie {
    root: TrieNode,
}

impl Trie {
    /// Create a new Trie.
    pub fn new() -> Self {
        Trie {
            root: TrieNode {
                children: HashMap::new(),
                is_end_of_word: false,
            }
        }
    }

    /// Insert a word into the Trie.
    pub fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for ch in word.chars() {
            node = node.children.entry(ch).or_insert_with(TrieNode::default);
        }
        node.is_end_of_word = true;
    }

    /// Returns true if the word exists in the Trie.
    pub fn search(&self, word: &str) -> bool {
        let mut node = &self.root;
        for ch in word.chars() {
            match node.children.get(&ch) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        node.is_end_of_word
    }

    /// Returns true if there is any word in the Trie that starts with the given prefix.
    pub fn starts_with(&self, prefix: &str) -> bool {
        let mut node = &self.root;
        for ch in prefix.chars() {
            match node.children.get(&ch) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        true
    }
}

// === Example usage & testing ===
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn basic_trie_operations() {
        let mut trie = Trie::new();

        trie.insert("apple");
        assert!(trie.search("apple"));
        assert!(!trie.search("app"));
        assert!(trie.starts_with("app"));

        trie.insert("app");
        assert!(trie.search("app"));
    }
}

fn main() {
    let mut trie = Trie::new();

    trie.insert("hello");
    trie.insert("helium");

    println!("Trie contains 'hello': {}", trie.search("hello"));        // true
    println!("Trie contains 'helix': {}", trie.search("helix"));        // false
    println!("Trie starts with 'hel': {}", trie.starts_with("hel"));    // true
    println!("Trie starts with 'hex': {}", trie.starts_with("hex"));    // false
}
```

