```rust
fn permutations<T: Clone>(items: Vec<T>) -> Vec<Vec<T>> {
    // Base case: The list is empty
    if items.len() == 0 {
        return vec![vec![]];
    }

    let mut result = Vec::new();

    for i in 0..items.len() {
        let mut rest = items.clone();
        let picked = rest.remove(i);

        // Recursively compute permutations of the rest
        for mut perm in permutations(rest) {
            perm.insert(0, picked.clone());
            result.push(perm);
        }
    }

    result
}

fn main() {
    let nums = vec![1, 2, 3];
    let perms = permutations(nums);

    for perm in perms {
        println!("{:?}", perm);
    }

    // Example with strings
    let strs = vec!["a", "b", "c"];
    for perm in permutations(strs) {
        println!("{:?}", perm);
    }
}
```

**How this works:**

- For every item, remove it from the list, recursively permute the rest, and prepend the item to every resulting permutation.
- The recursion finishes when the list is empty, returning a single empty permutation.

