Certainly! Below is a complete, self-contained implementation of **Dijkstra's shortest path algorithm** in Rust, using an adjacency list and a binary heap (as a priority queue). It finds the shortest distances from a given source node to all other nodes in a directed, weighted graph.

This code includes:

- `Edge` struct to represent edges.
- `Graph` struct managing adjacency lists.
- `dijkstra` function to compute shortest paths.
- An example main function demonstrating usage.

```rust
use std::cmp::Ordering;
use std::collections::{BinaryHeap, HashMap};

#[derive(Debug)]
struct Edge {
    node: usize,
    weight: usize,
}

#[derive(Debug)]
struct Graph {
    adj_list: Vec<Vec<Edge>>,
}

impl Graph {
    fn new(num_nodes: usize) -> Self {
        Graph {
            adj_list: vec![Vec::new(); num_nodes],
        }
    }

    fn add_edge(&mut self, from: usize, to: usize, weight: usize) {
        self.adj_list[from].push(Edge { node: to, weight });
    }
}

// Min-heap, because Rust's BinaryHeap is max-heap by default
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: usize,
    position: usize,
}

// Implement ordering for the priority queue (min-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice that we flip the ordering here, to make the heap a min-heap
        other.cost.cmp(&self.cost)
            .then_with(|| self.position.cmp(&other.position))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

/// Computes shortest paths from `start` to all other nodes.
/// Returns a vector of Option<usize> for distances.
/// If a node is unreachable, its entry is None.
fn dijkstra(graph: &Graph, start: usize) -> Vec<Option<usize>> {
    let n = graph.adj_list.len();
    let mut dist: Vec<Option<usize>> = vec![None; n];

    let mut heap = BinaryHeap::new();
    heap.push(State { cost: 0, position: start });

    while let Some(State { cost, position }) = heap.pop() {
        if let Some(current) = dist[position] {
            if cost >= current {
                continue; // Already found a shorter path
            }
        }

        dist[position] = Some(cost);

        for edge in &graph.adj_list[position] {
            let next = State {
                cost: cost + edge.weight,
                position: edge.node,
            };

            // Only push to heap if we haven't visited, or found a better path
            if dist[edge.node].map_or(true, |known| next.cost < known) {
                heap.push(next);
            }
        }
    }

    dist
}

fn main() {
    // Example usage:
    //
    // Graph:
    // 0 --(2)--> 1
    // 0 --(4)--> 2
    // 1 --(1)--> 2
    // 2 --(1)--> 3

    let mut graph = Graph::new(4);
    graph.add_edge(0, 1, 2);
    graph.add_edge(0, 2, 4);
    graph.add_edge(1, 2, 1);
    graph.add_edge(2, 3, 1);

    let start = 0;
    let shortest_paths = dijkstra(&graph, start);

    for (node, dist) in shortest_paths.iter().enumerate() {
        match dist {
            Some(d) => println!("Distance from node {} to {}: {}", start, node, d),
            None => println!("Node {} is unreachable from {}", node, start),
        }
    }
}
```

