```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use std::thread;

/// TokenBucket struct defining the rate limiter.
pub struct TokenBucket {
    capacity: u64,
    tokens: f64,
    refill_per_sec: f64,
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a new TokenBucket.
    ///
    /// * `capacity`: Maximum number of tokens in the bucket.
    /// * `refill_per_sec`: Number of tokens added per second.
    pub fn new(capacity: u64, refill_per_sec: f64) -> Self {
        Self {
            capacity,
            tokens: capacity as f64,
            refill_per_sec,
            last_refill: Instant::now(),
        }
    }

    /// Try to consume `amount` tokens.
    /// Returns true if successful, false if not enough tokens.
    pub fn try_take(&mut self, amount: u64) -> bool {
        self.refill();
        if self.tokens >= amount as f64 {
            self.tokens -= amount as f64;
            true
        } else {
            false
        }
    }

    /// Refill tokens based on elapsed time.
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);
        let to_add = self.refill_per_sec * elapsed.as_secs_f64();
        if to_add > 0.0 {
            self.tokens = (self.tokens + to_add).min(self.capacity as f64);
            self.last_refill = now;
        }
    }
}

fn main() {
    // Example: 5 tokens, refilling at 1 token per second.
    let bucket = Arc::new(Mutex::new(TokenBucket::new(5, 1.0)));

    let handles: Vec<_> = (0..10).map(|i| {
        let bucket = Arc::clone(&bucket);
        thread::spawn(move || {
            for _ in 0..3 {
                {
                    let mut limiter = bucket.lock().unwrap();
                    if limiter.try_take(1) {
                        println!("[Thread {i}] Allowed at {:?}", Instant::now());
                    } else {
                        println!("[Thread {i}] Rate Limited at {:?}", Instant::now());
                    }
                }
                thread::sleep(Duration::from_millis(700));
            }
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }
}
```

---

## How it works

- **TokenBucket** holds the bucket state (capacity, current tokens, refill rate, and last refill time).
- `try_take(amount)` tries to consume the requested tokens (default 1 in the example).
- Tokens are refilled as a function of elapsed time.
- Usage with `Arc<Mutex<>>` makes it safe for multi-threaded environments.

