Features:
- **Shunting Yard Algorithm** for parsing expressions into Reverse Polish Notation (RPN).
- **Evaluation** of the RPN.
- Handles parentheses, operator precedence, whitespace, and floating point numbers.

You can run or expand this easily in your Rust project.

---

```rust
use std::collections::VecDeque;

#[derive(Debug, PartialEq, Clone)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Star,
    Slash,
    LParen,
    RParen,
}

fn tokenize(expr: &str) -> Result<Vec<Token>, String> {
    let mut tokens = Vec::new();
    let chars: Vec<char> = expr.chars().collect();
    let mut i = 0;
    while i < chars.len() {
        match chars[i] {
            c if c.is_ascii_whitespace() => i += 1,
            c if c.is_ascii_digit() || c == '.' => {
                let start = i;
                let mut dot_count = if c == '.' { 1 } else { 0 };
                i += 1;
                while i < chars.len()
                    && (chars[i].is_ascii_digit() || (chars[i] == '.' && dot_count == 0))
                {
                    if chars[i] == '.' {
                        dot_count += 1;
                    }
                    i += 1;
                }
                let s: String = chars[start..i].iter().collect();
                let num: f64 = s.parse().map_err(|_| format!("Invalid number: '{}'", s))?;
                tokens.push(Token::Number(num));
            }
            '+' => {
                tokens.push(Token::Plus);
                i += 1;
            }
            '-' => {
                tokens.push(Token::Minus);
                i += 1;
            }
            '*' => {
                tokens.push(Token::Star);
                i += 1;
            }
            '/' => {
                tokens.push(Token::Slash);
                i += 1;
            }
            '(' => {
                tokens.push(Token::LParen);
                i += 1;
            }
            ')' => {
                tokens.push(Token::RParen);
                i += 1;
            }
            c => return Err(format!("Invalid character: '{}'", c)),
        }
    }
    Ok(tokens)
}

fn precedence(tok: &Token) -> u8 {
    match tok {
        Token::Plus | Token::Minus => 1,
        Token::Star | Token::Slash => 2,
        _ => 0,
    }
}

fn shunting_yard(tokens: &[Token]) -> Result<Vec<Token>, String> {
    let mut output: Vec<Token> = Vec::new();
    let mut op_stack: Vec<Token> = Vec::new();

    for token in tokens.iter() {
        match token {
            Token::Number(_) => output.push(token.clone()),
            Token::Plus | Token::Minus | Token::Star | Token::Slash => {
                while let Some(top) = op_stack.last() {
                    if let Token::Plus | Token::Minus | Token::Star | Token::Slash = top {
                        if precedence(top) >= precedence(token) {
                            output.push(op_stack.pop().unwrap());
                        } else {
                            break;
                        }
                    } else {
                        break;
                    }
                }
                op_stack.push(token.clone());
            }
            Token::LParen => op_stack.push(token.clone()),
            Token::RParen => {
                while let Some(top) = op_stack.last() {
                    if *top != Token::LParen {
                        output.push(op_stack.pop().unwrap());
                    } else {
                        break;
                    }
                }
                if op_stack.last() == Some(&Token::LParen) {
                    op_stack.pop();
                } else {
                    return Err("Mismatched parenthesis".to_string());
                }
            }
        }
    }
    while let Some(top) = op_stack.pop() {
        if top == Token::LParen || top == Token::RParen {
            return Err("Mismatched parenthesis".to_string());
        }
        output.push(top);
    }
    Ok(output)
}

fn eval_rpn(tokens: &[Token]) -> Result<f64, String> {
    let mut stack: Vec<f64> = Vec::new();
    for token in tokens {
        match token {
            Token::Number(n) => stack.push(*n),
            Token::Plus => {
                let b = stack.pop().ok_or("Missing operand")?;
                let a = stack.pop().ok_or("Missing operand")?;
                stack.push(a + b);
            }
            Token::Minus => {
                let b = stack.pop().ok_or("Missing operand")?;
                let a = stack.pop().ok_or("Missing operand")?;
                stack.push(a - b);
            }
            Token::Star => {
                let b = stack.pop().ok_or("Missing operand")?;
                let a = stack.pop().ok_or("Missing operand")?;
                stack.push(a * b);
            }
            Token::Slash => {
                let b = stack.pop().ok_or("Missing operand")?;
                if b == 0.0 {
                    return Err("Division by zero".to_string());
                }
                let a = stack.pop().ok_or("Missing operand")?;
                stack.push(a / b);
            }
            _ => return Err("Unexpected token in RPN".to_string()),
        }
    }
    if stack.len() == 1 {
        Ok(stack[0])
    } else {
        Err("Too many operands".to_string())
    }
}

fn evaluate(expr: &str) -> Result<f64, String> {
    let tokens = tokenize(expr)?;
    let rpn = shunting_yard(&tokens)?;
    eval_rpn(&rpn)
}

// ---- TESTING ----

fn main() {
    let examples = [
        "1 + 2 * 3",
        "(1 + 2) * 3",
        "10 / 2 - 5",
        "2 * (5 + 5 * 2) / 3",
        "3.5 * 2",
        "3 + 4 * 2 / (1 - 5)",
        "5 / 0",
        "1 + (2 * (2 + 3))",
        "1 + 2 * 3 + 4",
        "3 + 4 * 2 / (1 - 5) ^ 2 ^ 3", // Doesn't support ^ yet
    ];

    for expr in examples.iter() {
        match evaluate(expr) {
            Ok(result) => println!("{} = {}", expr, result),
            Err(e) => println!("{} : Error: {}", expr, e),
        }
    }
}
```

**How it works:**

- `tokenize()`: Splits the input string into a vector of tokens (numbers, operators, parentheses).
- `shunting_yard()`: Converts the infix token stream to postfix (RPN) using the shunting yard algorithm.
- `eval_rpn()`: Evaluates the postfix expression.
- `evaluate()`: All-in-one function to process a string and get the result.
- A `main()` function runs some example expressions.

---

**Usage:**
1. Save as `main.rs`.
2. Run with `cargo run`, or compile it.

**Limitations:**
- Does **not** support unary minus (e.g., "-3").
- Does **not** support exponentiation (`^`).
- Floating point parsing is supported.

