```rust
fn is_match(s: &str, p: &str) -> bool {
    fn helper(s: &[u8], p: &[u8]) -> bool {
        if p.is_empty() {
            return s.is_empty();
        }

        // Check if first chars match (with '.' or literal)
        let first_match = !s.is_empty() && (p[0] == b'.' || p[0] == s[0]);

        // Handle '*' as the second char in pattern
        if p.len() >= 2 && p[1] == b'*' {
            // Two choices:
            // 1. Skip "char*" -> move past 2 in pattern
            // 2. Use one more char if first matches
            helper(s, &p[2..]) || (first_match && helper(&s[1..], p))
        } else {
            // Move ahead if first matches
            first_match && helper(&s[1..], &p[1..])
        }
    }

    helper(s.as_bytes(), p.as_bytes())
}

fn main() {
    let tests = [
        ("aa", "a", false),
        ("aa", "a*", true),
        ("ab", ".*", true),
        ("mississippi", "mis*is*p*.", false),
        ("aab", "c*a*b", true),
        ("abc", "a.c", true),
        ("", "a*", true),
        ("", ".", false),
    ];

    for (s, p, expected) in &tests {
        let result = is_match(s, p);
        println!("is_match({:?}, {:?}) = {} (expected {})", s, p, result, expected);
        assert_eq!(result, *expected);
    }
}
```

