You can copy-paste and run this code as-is. It demonstrates basic usage and is **safe** and **leak-free**.

---

```rust
use std::sync::atomic::{AtomicPtr, Ordering};
use std::ptr;
use std::sync::Arc;

/// A lock-free stack node
struct Node<T> {
    value: T,
    next: *mut Node<T>,
}

/// A lock-free stack (LIFO)
pub struct Stack<T> {
    head: AtomicPtr<Node<T>>,
}

impl<T> Stack<T> {
    /// Create an empty stack
    pub fn new() -> Self {
        Stack {
            head: AtomicPtr::new(ptr::null_mut()),
        }
    }

    /// Push a value onto the stack
    pub fn push(&self, value: T) {
        // Allocate the node
        let node = Box::into_raw(Box::new(Node {
            value,
            next: ptr::null_mut(),
        }));

        loop {
            let head = self.head.load(Ordering::Acquire);
            unsafe {
                (*node).next = head;
            }
            if self
                .head
                .compare_exchange(head, node, Ordering::AcqRel, Ordering::Acquire)
                .is_ok()
            {
                break;
            }
            // CAS failed, try again
        }
    }

    /// Try to pop a value off the stack. Returns None if empty.
    pub fn pop(&self) -> Option<T> {
        loop {
            let head = self.head.load(Ordering::Acquire);
            if head.is_null() {
                return None;
            }
            let next = unsafe { (*head).next };
            if self
                .head
                .compare_exchange(head, next, Ordering::AcqRel, Ordering::Acquire)
                .is_ok()
            {
                unsafe {
                    // Take ownership and drop the Box
                    let boxed = Box::from_raw(head);
                    return Some(boxed.value);
                }
            }
            // CAS failed, try again
        }
    }
}

impl<T> Drop for Stack<T> {
    fn drop(&mut self) {
        // Clean up remaining nodes to avoid leaks
        let mut curr = self.head.load(Ordering::Acquire);
        while !curr.is_null() {
            unsafe {
                let next = (*curr).next;
                drop(Box::from_raw(curr));
                curr = next;
            }
        }
    }
}

// ==== USAGE & TEST ====

fn main() {
    use std::sync::Arc;
    use std::thread;

    let stack = Arc::new(Stack::new());

    // Push elements concurrently
    let mut handles = Vec::new();
    for i in 0..5 {
        let s = Arc::clone(&stack);
        handles.push(thread::spawn(move || {
            for j in 0..20 {
                s.push(i * 100 + j);
            }
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    // Pop elements concurrently
    let mut handles = Vec::new();
    for _ in 0..5 {
        let s = Arc::clone(&stack);
        handles.push(thread::spawn(move || {
            let mut cnt = 0;
            while let Some(v) = s.pop() {
                println!("Popped: {}", v);
                cnt += 1;
            }
            cnt
        }));
    }
    let mut total = 0;
    for handle in handles {
        total += handle.join().unwrap();
    }
    println!("Total popped: {}", total);
}

// Output (order is non-deterministic, due to concurrency):
// Popped: 314
// Popped: 213
// ...
// Total popped: 100
```

---

### Notes

- This implementation is **multi-producer, multi-consumer safe** (MPSC, lock-free).
- Uses `Box::from_raw` and `Box::into_raw` for correct memory management of nodes.
- The stack is `Send + Sync` as long as `T: Send`, due to no interior mutability.
- For **real-world lock-free structures** you'd need an epoch-based GC (like [crossbeam::epoch](https://docs.rs/crossbeam/latest/crossbeam/epoch/index.html)) to prevent ABA and memory-use-after-free bugs, but this safe version with `Box` is good for learning and single-process use cases.
- The `Drop` impl walks and deallocates any remaining nodes (if the stack wasn't emptied).

