Certainly! Below is a full implementation of a **persistent (immutable) red-black tree** in Rust. This tree is:

- Fully immutable (every update returns a new tree, old versions remain usable).
- Correctly balanced with red-black properties.
- Provides `insert`, `get`, and in-order iteration.
- Uses **reference counting** (`Rc`) internally for efficient structural sharing.

### Complete Code

```rust
use std::rc::Rc;
use std::cmp::Ordering;

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum Color {
    Red,
    Black,
}

type Link<K, V> = Option<Rc<Node<K, V>>>;

#[derive(Clone)]
struct Node<K, V> {
    color: Color,
    key: K,
    value: V,
    left: Link<K, V>,
    right: Link<K, V>,
}

#[derive(Clone)]
pub struct RedBlackTree<K, V> {
    root: Link<K, V>,
}

impl<K: Ord + Clone, V: Clone> RedBlackTree<K, V> {
    pub fn new() -> Self {
        RedBlackTree { root: None }
    }

    /// Get a reference to value by key.
    pub fn get(&self, key: &K) -> Option<V> {
        let mut node = self.root.as_ref();
        while let Some(n) = node {
            match key.cmp(&n.key) {
                Ordering::Less => node = n.left.as_ref(),
                Ordering::Greater => node = n.right.as_ref(),
                Ordering::Equal => return Some(n.value.clone()),
            }
        }
        None
    }

    /// Insert a key-value pair, returning a new tree.
    pub fn insert(&self, key: K, value: V) -> Self {
        let (new_root, _) = insert_rec(self.root.clone(), key, value);
        // The root must always be black.
        let black_root = new_root.map(|n| {
            if n.color == Color::Black {
                n
            } else {
                Rc::new(Node { color: Color::Black, ..(*n).clone() })
            }
        });
        RedBlackTree { root: black_root }
    }

    /// In-order traverse (for debugging/testing)
    pub fn iter(&self) -> Vec<(K, V)>
        where K: std::fmt::Debug, V: std::fmt::Debug
    {
        let mut v = Vec::new();
        fn traverse<K: Clone, V: Clone>(n: &Link<K,V>, acc: &mut Vec<(K, V)>) {
            if let Some(n) = n {
                traverse(&n.left, acc);
                acc.push((n.key.clone(), n.value.clone()));
                traverse(&n.right, acc);
            }
        }
        traverse(&self.root, &mut v);
        v
    }
}

// LEFT-LEANING Red-Black Tree implementation

fn is_red<K, V>(node: &Link<K, V>) -> bool {
    node.as_ref().map_or(false, |n| n.color == Color::Red)
}

fn rotate_left<K: Clone, V: Clone>(h: Rc<Node<K,V>>) -> Rc<Node<K,V>> {
    let x = h.right.as_ref().expect("rotate_left: right child must be red").clone();
    Rc::new(Node {
        color: h.color,
        key: x.key.clone(),
        value: x.value.clone(),
        left: Some(Rc::new(Node {
            color: Color::Red,
            key: h.key.clone(),
            value: h.value.clone(),
            left: h.left.clone(),
            right: x.left.clone(),
        })),
        right: x.right.clone(),
    })
}

fn rotate_right<K: Clone, V: Clone>(h: Rc<Node<K,V>>) -> Rc<Node<K,V>> {
    let x = h.left.as_ref().expect("rotate_right: left child must be red").clone();
    Rc::new(Node {
        color: h.color,
        key: x.key.clone(),
        value: x.value.clone(),
        left: x.left.clone(),
        right: Some(Rc::new(Node {
            color: Color::Red,
            key: h.key.clone(),
            value: h.value.clone(),
            left: x.right.clone(),
            right: h.right.clone(),
        })),
    })
}

fn flip_colors<K: Clone, V: Clone>(h: &Rc<Node<K,V>>) -> Rc<Node<K,V>> {
    Rc::new(Node {
        color: match h.color { Color::Red => Color::Black, Color::Black => Color::Red },
        key: h.key.clone(),
        value: h.value.clone(),
        left: h.left.clone().map(|left| Rc::new(Node {
            color: Color::Black,
            ..(*left).clone()
        })),
        right: h.right.clone().map(|right| Rc::new(Node {
            color: Color::Black,
            ..(*right).clone()
        })),
    })
}

/// Returns (possibly rebalanced tree, was_new_key_inserted)
fn insert_rec<K: Ord + Clone, V: Clone>(h: Link<K, V>, key: K, value: V) -> (Link<K, V>, bool) {
    if let Some(node) = h {
        let mut h = node.clone();
        let mut inserted = false;

        match key.cmp(&h.key) {
            Ordering::Less => {
                let (new_left, did_insert) = insert_rec(h.left.clone(), key, value);
                h.left = new_left;
                inserted = did_insert;
            }
            Ordering::Greater => {
                let (new_right, did_insert) = insert_rec(h.right.clone(), key, value);
                h.right = new_right;
                inserted = did_insert;
            }
            Ordering::Equal => {
                // Update value, no insertion
                h.value = value;
            }
        }

        // Rebalance (Left-Leaning Red-Black Tree rules)
        let mut h = Rc::new(h);

        if is_red(&h.right) && !is_red(&h.left) {
            h = rotate_left(h);
        }
        if is_red(&h.left) && is_red(&h.left.as_ref().unwrap().left) {
            h = rotate_right(h);
        }
        if is_red(&h.left) && is_red(&h.right) {
            h = flip_colors(&h);
        }

        (Some(h), inserted)
    } else {
        // New node is always red
        let node = Node {
            color: Color::Red,
            key,
            value,
            left: None,
            right: None,
        };
        (Some(Rc::new(node)), true)
    }
}

// -------------------------------
// EXAMPLE USAGE
// -------------------------------
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn rb_persistent_insert_and_get() {
        let t0: RedBlackTree<i32, &str> = RedBlackTree::new();
        let t1 = t0.insert(10, "a");
        let t2 = t1.insert(20, "b");
        let t3 = t2.insert(5, "c");

        assert_eq!(t0.get(&10), None);
        assert_eq!(t1.get(&10), Some("a"));
        assert_eq!(t2.get(&20), Some("b"));
        assert_eq!(t3.get(&5), Some("c"));

        // old versions still work
        assert_eq!(t1.get(&20), None);
        assert_eq!(t2.get(&5), None);

        // iteration is in order
        assert_eq!(t3.iter(), vec![(5, "c"), (10, "a"), (20, "b")]);
    }

    #[test]
    fn rb_persistent_update() {
        let t0: RedBlackTree<i32, &str> = RedBlackTree::new();
        let t1 = t0.insert(7, "seven");
        let t2 = t1.insert(7, "seven again");

        assert_eq!(t1.get(&7), Some("seven"));
        assert_eq!(t2.get(&7), Some("seven again"));
    }
}

// Optionally, add a `main` to see it in action outside of tests:
