Certainly! Below is a complete, working Rust implementation of **Lamport timestamps** for distributed ordering.

This implementation includes:

- The `LamportClock` struct;
- Methods for incrementing the clock (on local events), receiving a message (with another timestamp), and comparing timestamps (for ordering);
- All code in a single file, with an example demonstrating usage.

---

```rust
use std::cmp::{Ordering, max};

/// LamportClock represents a Lamport logical clock.
/// Each process has its own LamportClock instance.
///
#[derive(Debug, Clone, Copy, Eq, PartialEq)]
pub struct LamportClock {
    pub timestamp: u64,
    pub process_id: u64,
}

impl LamportClock {
    /// Creates a new Lamport clock for a given process.
    pub fn new(process_id: u64) -> LamportClock {
        LamportClock {
            timestamp: 0,
            process_id,
        }
    }

    /// To be called for each local event.
    pub fn tick(&mut self) {
        self.timestamp += 1;
    }

    /// To be called when a message is received, along with the other timestamp.
    /// - Increments own time to be greater than the received timestamp.
    pub fn receive(&mut self, other: LamportClock) {
        self.timestamp = max(self.timestamp, other.timestamp) + 1;
    }

    /// Returns current timestamp with process id.
    pub fn value(&self) -> (u64, u64) {
        (self.timestamp, self.process_id)
    }
}

// Implement ordering for LamportClock: Order by timestamp, break ties by process_id.
impl Ord for LamportClock {
    fn cmp(&self, other: &Self) -> Ordering {
        match self.timestamp.cmp(&other.timestamp) {
            Ordering::Less => Ordering::Less,
            Ordering::Greater => Ordering::Greater,
            Ordering::Equal => self.process_id.cmp(&other.process_id),
        }
    }
}

impl PartialOrd for LamportClock {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// --- Example usage ---

fn main() {
    // Create clocks for two processes:
    let mut proc1 = LamportClock::new(1);
    let mut proc2 = LamportClock::new(2);

    // Local event on proc1
    proc1.tick();
    println!("Proc1 after local event: {:?}", proc1);

    // Proc1 sends a message to proc2 (along with its clock)
    let msg_timestamp = proc1;

    // Proc2 receives the message
    proc2.receive(msg_timestamp);
    println!("Proc2 after receiving message: {:?}", proc2);

    // Another local event on proc2
    proc2.tick();
    println!("Proc2 after another local event: {:?}", proc2);

    // Compare events from both clocks
    println!(
        "Ordering: Proc1 ({:?}) vs Proc2 ({:?}) => {:?}",
        proc1,
        proc2,
        proc1.cmp(&proc2)
    );
}

// --- Sample Output (will match this pattern, depending on event order) ---
// Proc1 after local event: LamportClock { timestamp: 1, process_id: 1 }
// Proc2 after receiving message: LamportClock { timestamp: 2, process_id: 2 }
// Proc2 after another local event: LamportClock { timestamp: 3, process_id: 2 }
// Ordering: Proc1 (LamportClock { timestamp: 1, process_id: 1 }) vs Proc2 (LamportClock { timestamp: 3, process_id: 2 }) => Less
```

---

**How to use:**  
- Copy the code above into `main.rs`.
- `cargo run`
- You can simulate more processes, more messages, etc., using this `LamportClock` primitive.

