Certainly! Below is a complete, **idiomatic Rust implementation of a skip list** supporting insertion, search, and deletion. This implementation is generic over key and value types with ordering, uses `rand` for level generation, and ensures memory safety with `Rc` and `RefCell`.

#### `Cargo.toml` Dependency

First, add the [`rand`](https://crates.io/crates/rand) crate to your `Cargo.toml`:

```toml
[dependencies]
rand = "0.8"
```

---

## `skip_list.rs` Implementation

```rust
use rand::prelude::*;
use std::cell::RefCell;
use std::cmp::Ordering;
use std::rc::Rc;

const MAX_LEVEL: usize = 16;
const P: f64 = 0.5; // Probability for random level

type Link<K, V> = Option<Rc<RefCell<Node<K, V>>>>;

#[derive(Debug)]
struct Node<K, V> {
    key: Option<K>,
    value: Option<V>,
    // Forward pointers, one per level
    forwards: Vec<Link<K, V>>,
}

impl<K, V> Node<K, V> {
    fn new(key: Option<K>, value: Option<V>, level: usize) -> Rc<RefCell<Self>> {
        Rc::new(RefCell::new(Node {
            key,
            value,
            forwards: vec![None; level],
        }))
    }
}

pub struct SkipList<K: Ord, V> {
    head: Rc<RefCell<Node<K, V>>>,
    level: usize,
    length: usize,
}

impl<K: Ord, V> SkipList<K, V> {
    pub fn new() -> Self {
        let head = Node::new(None, None, MAX_LEVEL);
        SkipList {
            head,
            level: 1,
            length: 0,
        }
    }

    /// Generates a random level for a new node.
    fn random_level() -> usize {
        let mut lvl = 1;
        let mut rng = thread_rng();
        while rng.gen::<f64>() < P && lvl < MAX_LEVEL {
            lvl += 1;
        }
        lvl
    }

    /// Search for a key; returns reference to value if found
    pub fn get(&self, key: &K) -> Option<V>
    where
        K: Clone,
        V: Clone,
    {
        let mut curr = Rc::clone(&self.head);
        for i in (0..self.level).rev() {
            loop {
                let next_opt = curr.borrow().forwards[i].as_ref().map(Rc::clone);
                match next_opt {
                    Some(next) => {
                        let next_key = next.borrow().key.as_ref().unwrap();
                        match next_key.cmp(key) {
                            Ordering::Less => {
                                curr = next;
                            }
                            _ => break,
                        }
                    }
                    None => break,
                }
            }
        }
        // At level 0, check if the next node is the searched node
        let next = self.head.borrow().forwards[0].as_ref().map(Rc::clone);
        if let Some(node) = next {
            let nkey = node.borrow().key.as_ref().unwrap();
            if nkey == key {
                return node.borrow().value.clone();
            }
        }
        // Or we might have stopped at curr
        let next = curr.borrow().forwards[0].as_ref().map(Rc::clone);
        if let Some(node) = next {
            if let Some(nkey) = node.borrow().key.as_ref() {
                if nkey == key {
                    return node.borrow().value.clone();
                }
            }
        }
        None
    }

    /// Insert or update (key, value)
    pub fn insert(&mut self, key: K, value: V) {
        let mut update: Vec<Rc<RefCell<Node<K, V>>>> = vec![Rc::clone(&self.head); MAX_LEVEL];

        let mut curr = Rc::clone(&self.head);

        // Find update points
        for i in (0..self.level).rev() {
            loop {
                let next_opt = curr.borrow().forwards[i].as_ref().map(Rc::clone);
                match next_opt {
                    Some(next) => {
                        let next_key = next.borrow().key.as_ref().unwrap();
                        if next_key < &key {
                            curr = next;
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
            update[i] = Rc::clone(&curr);
        }

        // See if key exists
        let next = update[0].borrow().forwards[0].as_ref().map(Rc::clone);
        if let Some(node) = next {
            if let Some(nkey) = node.borrow().key.as_ref() {
                if nkey == &key {
                    node.borrow_mut().value = Some(value);
                    return;
                }
            }
        }

        // Insert new node
        let node_level = Self::random_level();
        if node_level > self.level {
            for i in self.level..node_level {
                update[i] = Rc::clone(&self.head);
            }
            self.level = node_level;
        }

        let new_node = Node::new(Some(key), Some(value), node_level);

        for i in 0..node_level {
            let next = update[i].borrow().forwards[i].take();
            new_node.borrow_mut().forwards[i] = next.clone();
            update[i].borrow_mut().forwards[i] = Some(Rc::clone(&new_node));
        }
        self.length += 1;
    }

    /// Remove by key
    pub fn remove(&mut self, key: &K) -> bool {
        let mut update: Vec<Rc<RefCell<Node<K, V>>>> = vec![Rc::clone(&self.head); MAX_LEVEL];
        let mut curr = Rc::clone(&self.head);

        for i in (0..self.level).rev() {
            loop {
                let next_opt = curr.borrow().forwards[i].as_ref().map(Rc::clone);
                match next_opt {
                    Some(next) => {
                        let next_key = next.borrow().key.as_ref().unwrap();
                        if next_key < key {
                            curr = next;
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
            update[i] = Rc::clone(&curr);
        }

        // Check if node exists
        let target = curr.borrow().forwards[0].as_ref().map(Rc::clone);
        if let Some(node) = target {
            if node.borrow().key.as_ref().unwrap() == key {
                for i in 0..self.level {
                    if update[i].borrow().forwards[i].as_ref().map_or(false, |pred| {
                        Rc::ptr_eq(pred, &node)
                    }) {
                        let next = node.borrow().forwards[i].as_ref().map(Rc::clone);
                        update[i].borrow_mut().forwards[i] = next;
                    }
                }
                // May need to decrease level
                while self.level > 1
                    && self.head.borrow().forwards[self.level - 1].is_none()
                {
                    self.level -= 1;
                }
                self.length -= 1;
                return true;
            }
        }
        false
    }

    /// Returns the number of elements in the skip list.
    pub fn len(&self) -> usize {
        self.length
    }

    /// Returns true if the skip list is empty.
    pub fn is_empty(&self) -> bool {
        self.length == 0
    }
}

// Optional: Iterator
pub struct Iter<'a, K: Ord + Clone, V: Clone> {
    next: Option<Rc<RefCell<Node<K, V>>>>,
    phantom: std::marker::PhantomData<&'a SkipList<K, V>>,
}

impl<'a, K: Ord + Clone, V: Clone> Iterator for Iter<'a, K, V> {
    type Item = (K, V);

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(curr) = &self.next {
            let curr_b = curr.borrow();
            if let (Some(ref k), Some(ref v)) = (&curr_b.key, &curr_b.value) {
                let result = (k.clone(), v.clone());
                self.next = curr_b.forwards[0].as_ref().map(Rc::clone);
                return Some(result);
            }
        }
        None
    }
}

impl<K: Ord + Clone, V: Clone> SkipList<K, V> {
    pub fn iter(&self) -> Iter<'_, K, V> {
        Iter {
            next: self.head.borrow().forwards[0].as_ref().map(Rc::clone),
            phantom: std::marker::PhantomData,
        }
    }
}
```

