Certainly! Below is a **complete working Rust implementation** that solves the N-Queens problem using backtracking. The code defines a function to find all solutions and prints them. It's easy to set `N` to any size you'd like.

```rust
fn main() {
    let n = 8; // Change this for different N
    let solutions = solve_n_queens(n);

    println!("Number of solutions for {}-Queens: {}", n, solutions.len());
    for (i, sol) in solutions.iter().enumerate() {
        println!("Solution #{}:", i + 1);
        print_board(sol);
    }
}

/// Returns a vector of solutions, each represented as a vector of column indices.
/// `board[i] = j` means row i has the queen in column j.
fn solve_n_queens(n: usize) -> Vec<Vec<usize>> {
    let mut solutions = Vec::new();
    let mut board = Vec::new();
    let mut cols = vec![false; n];
    let mut diag1 = vec![false; 2 * n - 1]; // row + col
    let mut diag2 = vec![false; 2 * n - 1]; // row - col + n - 1

    fn solve(
        n: usize,
        row: usize,
        board: &mut Vec<usize>,
        cols: &mut Vec<bool>,
        diag1: &mut Vec<bool>,
        diag2: &mut Vec<bool>,
        solutions: &mut Vec<Vec<usize>>
    ) {
        if row == n {
            solutions.push(board.clone());
            return;
        }
        for col in 0..n {
            let d1 = row + col;
            let d2 = row as isize - col as isize + n as isize - 1;
            if !cols[col] && !diag1[d1] && !diag2[d2 as usize] {
                board.push(col);
                cols[col] = true;
                diag1[d1] = true;
                diag2[d2 as usize] = true;
                solve(n, row + 1, board, cols, diag1, diag2, solutions);
                board.pop();
                cols[col] = false;
                diag1[d1] = false;
                diag2[d2 as usize] = false;
            }
        }
    }

    solve(
        n,
        0,
        &mut board,
        &mut cols,
        &mut diag1,
        &mut diag2,
        &mut solutions,
    );

    solutions
}

/// Pretty-print the board from a vector of column indices.
fn print_board(solution: &[usize]) {
    let n = solution.len();
    for &col in solution {
        for c in 0..n {
            if c == col {
                print!("Q ");
            } else {
                print!(". ");
            }
        }
        println!();
    }
    println!();
}
```

