fn main() {
    let mut data = vec![10.0, 2.5, 5.4, 8.2, 1.7];

    // The single expression:
    let (sorted_reversed, median, std_dev) = {
        let mut v = data.clone();
        v.sort_by(|a, b| a.partial_cmp(b).unwrap());
        v.reverse();

        let n = v.len();
        let median = if n % 2 == 0 {
            (v[n / 2 - 1] + v[n / 2]) / 2.0
        } else {
            v[n / 2]
        };
        let mean = v.iter().sum::<f64>() / n as f64;
        let std_dev = (v.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n as f64).sqrt();

        (v, median, std_dev)
    };

    println!("Sorted & reversed: {:?}", sorted_reversed);
    println!("Median: {}", median);
    println!("Standard deviation: {}", std_dev);
}
```

