use std::f64::consts::FRAC_1_SQRT_2;
type C = num_complex::Complex<f64>;
type State = Vec<C>;

fn kron(a: &[C], b: &[C]) -> Vec<C> {
    a.iter().flat_map(|&x| b.iter().map(move |&y| x * y)).collect()
}

fn apply_gate(state: &mut State, gate: &[[C; 2]; 2], qubit: usize, n: usize) {
    let size = 1 << n;
    for i in 0..size {
        if (i >> qubit) & 1 == 0 {
            let j = i | (1 << qubit);
            let (a, b) = (state[i], state[j]);
            state[i] = gate[0][0] * a + gate[0][1] * b;
            state[j] = gate[1][0] * a + gate[1][1] * b;
        }
    }
}

fn apply_cnot(state: &mut State, control: usize, target: usize, n: usize) {
    let size = 1 << n;
    for i in 0..size {
        if ((i >> control) & 1 == 1) && ((i >> target) & 1 == 0) {
            let j = i | (1 << target);
            state.swap(i, j);
        }
    }
}

fn measure(state: &State) -> usize {
    let mut rng = rand::random::<f64>();
    for (i, amp) in state.iter().enumerate() {
        let p = amp.norm_sqr();
        if rng < p { return i; }
        rng -= p;
    }
    state.len() - 1
}

fn main() {
    let n = 2;
    let mut state = vec![C::new(0.0,0.0); 1 << n];
    state[0] = C::new(1.0,0.0);

    let hadamard = [
        [C::new(FRAC_1_SQRT_2,0.0), C::new(FRAC_1_SQRT_2,0.0)],
        [C::new(FRAC_1_SQRT_2,0.0), C::new(-FRAC_1_SQRT_2,0.0)],
    ];

    apply_gate(&mut state, &hadamard, 0, n);
    apply_cnot(&mut state, 0, 1, n);

    let res = measure(&state);
    println!("Measurement: |{:0width$b}>", res, width=n);
}
```

