#[derive(Debug)]
enum NestedList {
    Int(i32),
    List(Vec<NestedList>),
}

fn flatten(nested: &NestedList) -> Vec<i32> {
    let mut result = Vec::new();
    match nested {
        NestedList::Int(n) => result.push(*n),
        NestedList::List(list) => {
            for item in list {
                result.extend(flatten(item));
            }
        }
    }
    result
}

