Certainly! Below is a complete, working implementation of an **LRU (Least Recently Used) cache** in Rust.

This design uses:
- A `HashMap` for O(1) lookups.
- A doubly linked list (`std::collections::LinkedList`) to track LRU order.
- The cache supports `get` and `put`.

### The Code

```rust
use std::collections::{HashMap, LinkedList};
use std::hash::Hash;

pub struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, (V, LinkedListNodeRef<K>)>,
    list: LinkedList<K>,
}

type LinkedListNodeRef<K> = *mut K; // Unsafe raw pointer for in-place manipulation

impl<K, V> LruCache<K, V>
where
    K: Clone + Eq + Hash,
    V: Clone,
{
    pub fn new(capacity: usize) -> Self {
        Self {
            capacity,
            map: HashMap::new(),
            list: LinkedList::new(),
        }
    }

    pub fn get(&mut self, key: &K) -> Option<V> {
        if let Some((value, _)) = self.map.get(key) {
            // Move the key to the front (most recently used)
            self.touch_key(key);
            Some(value.clone())
        } else {
            None
        }
    }

    pub fn put(&mut self, key: K, value: V) {
        if self.map.contains_key(&key) {
            // Update value and move to front
            self.touch_key(&key);
            if let Some((v, _)) = self.map.get_mut(&key) {
                *v = value;
            }
        } else {
            // Insert new key, evict if needed
            if self.map.len() == self.capacity {
                self.evict_lru();
            }
            self.list.push_front(key.clone());
            // pointer to the head entry
            let head_ptr: LinkedListNodeRef<K> = self.list.front_mut().unwrap() as *mut K;
            self.map.insert(key, (value, head_ptr));
        }
    }

    // Helper: Move a key to the front of the list
    fn touch_key(&mut self, key: &K) {
        // Remove key from wherever it is, and push to front
        let mut idx = 0;
        let mut found = false;

        for (i, v) in self.list.iter_mut().enumerate() {
            if v == key {
                idx = i;
                found = true;
                break;
            }
        }
        if found {
            // Remove from idx and push_front
            let mut cursor = self.list.cursor_front_mut();
            for _ in 0..idx {
                cursor.move_next();
            }
            let removed = cursor.remove_current();
            if let Some(k) = removed {
                self.list.push_front(k);
            }
        }
    }

    fn evict_lru(&mut self) {
        if let Some(lru_key) = self.list.pop_back() {
            self.map.remove(&lru_key);
        }
    }
}

// -----------------
// Example Usage
// -----------------
fn main() {
    let mut lru = LruCache::new(2);

    lru.put(1, "one");
    lru.put(2, "two");
    println!("{:?}", lru.get(&1)); // Some("one")

    lru.put(3, "three"); // Evicts key 2 ("two")
    println!("{:?}", lru.get(&2)); // None

    lru.put(4, "four"); // Evicts key 1 ("one")
    println!("{:?}", lru.get(&1)); // None
    println!("{:?}", lru.get(&3)); // Some("three")
    println!("{:?}", lru.get(&4)); // Some("four")
}
```

---

## Notes

- This implementation is simplified for clarity and correctness.
- If you want maximum efficiency, use a [third-party crate like `lru`](https://docs.rs/lru/latest/lru/) or use unsafe code + custom linked lists for zero overhead.
- The current design is **safe** and idiomatic, suitable for learning and moderate use cases.

