pub struct TreeNode {
    pub val: i32,
    pub left: Option<Rc<RefCell<TreeNode>>>,
    pub right: Option<Rc<RefCell<TreeNode>>>,
}

impl TreeNode {
    #[inline]
    pub fn new(val: i32) -> Self {
        TreeNode {
            val,
            left: None,
            right: None,
        }
    }
}

struct Codec;

impl Codec {
    /// Encodes a tree to a single string.
    pub fn serialize(&self, root: Option<Rc<RefCell<TreeNode>>>) -> String {
        fn helper(node: &Option<Rc<RefCell<TreeNode>>>, out: &mut Vec<String>) {
            match node {
                Some(n) => {
                    out.push(n.borrow().val.to_string());
                    helper(&n.borrow().left, out);
                    helper(&n.borrow().right, out);
                }
                None => out.push("#".into()),
            }
        }
        let mut out = Vec::new();
        helper(&root, &mut out);
        out.join(",")
    }

    /// Decodes your encoded data to tree.
    pub fn deserialize(&self, data: String) -> Option<Rc<RefCell<TreeNode>>> {
        fn helper<'a, I>(iter: &mut I) -> Option<Rc<RefCell<TreeNode>>>
        where
            I: Iterator<Item = &'a str>,
        {
            match iter.next() {
                Some("#") => None,
                Some(val) => {
                    let n = Rc::new(RefCell::new(TreeNode::new(val.parse().unwrap())));
                    n.borrow_mut().left = helper(iter);
                    n.borrow_mut().right = helper(iter);
                    Some(n)
                }
                None => None,
            }
        }
        let mut iter = data.split(",");
        helper(&mut iter)
    }
}

// Example usage:
fn main() {
    // Build a test tree:      1
    //                        / \
    //                       2   3
    //                          / \
    //                         4   5
    let node = Rc::new(RefCell::new(TreeNode {
        val: 1,
        left: Some(Rc::new(RefCell::new(TreeNode::new(2)))),
        right: Some(Rc::new(RefCell::new(TreeNode {
            val: 3,
            left: Some(Rc::new(RefCell::new(TreeNode::new(4)))),
            right: Some(Rc::new(RefCell::new(TreeNode::new(5)))),
        }))),
    }));

    let codec = Codec {};
    let serialized = codec.serialize(Some(node.clone()));
    println!("Serialized: {}", serialized);

    let deserialized = codec.deserialize(serialized.clone());
    println!("Deserialized (root value): {}", deserialized.unwrap().borrow().val);
}
```

### Output
```
Serialized: 1,2,#,#,3,4,#,#,5,#,#
Deserialized (root value): 1
```

## Notes

- This code represents empty nodes as `"#"`.
- It supports trees with arbitrary structure, including empty trees.
- You can adapt it for `Option<Box<TreeNode>>` if you prefer not to use `Rc<RefCell<>>`. The above is in line with LeetCode's Rust conventions.

