```rust
use std::collections::HashMap;

#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

pub struct Trie {
    root: TrieNode,
}

impl Trie {
    /// Creates a new Trie
    pub fn new() -> Self {
        Trie { root: TrieNode::default() }
    }

    /// Inserts a word into the Trie
    pub fn insert(&mut self, word: &str) {
        let mut current = &mut self.root;
        for ch in word.chars() {
            current = current.children.entry(ch).or_insert_with(TrieNode::default);
        }
        current.is_end_of_word = true;
    }

    /// Returns true if the word is in the Trie
    pub fn search(&self, word: &str) -> bool {
        let mut current = &self.root;
        for ch in word.chars() {
            match current.children.get(&ch) {
                Some(node) => current = node,
                None => return false,
            }
        }
        current.is_end_of_word
    }

    /// Returns true if there is any word in the trie starting with the given prefix
    pub fn starts_with(&self, prefix: &str) -> bool {
        let mut current = &self.root;
        for ch in prefix.chars() {
            match current.children.get(&ch) {
                Some(node) => current = node,
                None => return false,
            }
        }
        true
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_trie() {
        let mut trie = Trie::new();

        trie.insert("apple");
        assert_eq!(trie.search("apple"), true);
        assert_eq!(trie.search("app"), false);
        assert_eq!(trie.starts_with("app"), true);

        trie.insert("app");
        assert_eq!(trie.search("app"), true);
        assert_eq!(trie.starts_with("appl"), true);

        trie.insert("apex");
        assert_eq!(trie.search("apex"), true);
        assert_eq!(trie.search("ape"), false);

        trie.insert("bat");
        assert_eq!(trie.search("bat"), true);
        assert_eq!(trie.starts_with("ba"), true);
        assert_eq!(trie.starts_with("bats"), false);
    }
}
```

