## Full Token Bucket Implementation in Rust

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

/// The TokenBucket struct
pub struct TokenBucket {
    capacity: usize,
    tokens: f64,
    refill_rate: f64,        // tokens per second
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a new TokenBucket.
    ///
    /// * `capacity` - Maximum number of tokens in the bucket
    /// * `refill_rate` - Tokens to add per second
    pub fn new(capacity: usize, refill_rate: f64) -> Self {
        Self {
            capacity,
            tokens: capacity as f64,
            refill_rate,
            last_refill: Instant::now(),
        }
    }

    /// Attempts to take `amount` tokens from the bucket.
    ///
    /// Returns true if enough tokens were present; false otherwise.
    pub fn try_acquire(&mut self, amount: usize) -> bool {
        self.refill();

        if self.tokens >= amount as f64 {
            self.tokens -= amount as f64;
            true
        } else {
            false
        }
    }

    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);
        let refill_tokens = self.refill_rate * (elapsed.as_secs_f64());
        self.tokens = (self.tokens + refill_tokens).min(self.capacity as f64);
        self.last_refill = now;
    }
}


/// Thread-safe wrapper using Arc<Mutex<_>>
#[derive(Clone)]
pub struct SharedTokenBucket {
    inner: Arc<Mutex<TokenBucket>>
}

impl SharedTokenBucket {
    pub fn new(capacity: usize, refill_rate: f64) -> Self {
        Self {
            inner: Arc::new(Mutex::new(TokenBucket::new(capacity, refill_rate)))
        }
    }

    /// Attempts to take tokens from the bucket.
    pub fn try_acquire(&self, amount: usize) -> bool {
        let mut bucket = self.inner.lock().unwrap();
        bucket.try_acquire(amount)
    }
}


/// Optionally, an async version (with Tokio's Mutex)
#[cfg(feature = "async")]
pub mod async_impl {
    use tokio::sync::Mutex;
    use std::sync::Arc;
    use std::time::{Duration, Instant};

    pub struct TokenBucket {
        capacity: usize,
        tokens: f64,
        refill_rate: f64,
        last_refill: Instant,
    }

    impl TokenBucket {
        pub fn new(capacity: usize, refill_rate: f64) -> Self {
            Self {
                capacity,
                tokens: capacity as f64,
                refill_rate,
                last_refill: Instant::now(),
            }
        }

        pub fn try_acquire(&mut self, amount: usize) -> bool {
            let now = Instant::now();
            let elapsed = now.duration_since(self.last_refill);
            let refill_tokens = self.refill_rate * (elapsed.as_secs_f64());
            self.tokens = (self.tokens + refill_tokens).min(self.capacity as f64);
            self.last_refill = now;

            if self.tokens >= amount as f64 {
                self.tokens -= amount as f64;
                true
            } else {
                false
            }
        }
    }

    #[derive(Clone)]
    pub struct SharedTokenBucket {
        inner: Arc<Mutex<TokenBucket>>
    }

    impl SharedTokenBucket {
        pub fn new(capacity: usize, refill_rate: f64) -> Self {
            Self {
                inner: Arc::new(Mutex::new(TokenBucket::new(capacity, refill_rate)))
            }
        }

        pub async fn try_acquire(&self, amount: usize) -> bool {
            let mut bucket = self.inner.lock().await;
            bucket.try_acquire(amount)
        }
    }
}

/// Basic usage and test cases
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_simple_bucket() {
        let mut bucket = TokenBucket::new(10, 10.0); // 10 tokens, 10/sec

        // Initial tokens are full
        assert!(bucket.try_acquire(5));
        assert!(bucket.try_acquire(5));
        assert!(!bucket.try_acquire(1)); // now empty

        // Wait to refill
        std::thread::sleep(Duration::from_millis(110));
        assert!(bucket.try_acquire(1));
    }

    #[test]
    fn test_shared_bucket() {
        let limiter = SharedTokenBucket::new(2, 1.0);

        assert!(limiter.try_acquire(1));
        assert!(limiter.try_acquire(1));
        assert!(!limiter.try_acquire(1));
    }
}


/// Usage Example
