Certainly! Below is a complete, working implementation of a **bounded blocking queue** in Rust, using standard concurrency primitives (`Mutex` and `Condvar`). This queue supports multiple producers and consumers, and both `push` and `pop` block if the queue is full/empty, respectively.

For illustration, I include a `main` function with an example of how you can use it.

---

```rust
use std::{
    collections::VecDeque,
    sync::{Arc, Mutex, Condvar},
    thread,
    time::Duration,
};

// BoundedBlockingQueue definition
pub struct BoundedBlockingQueue<T> {
    capacity: usize,
    queue: Mutex<VecDeque<T>>,
    not_empty: Condvar,
    not_full: Condvar,
}

impl<T> BoundedBlockingQueue<T> {
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "Capacity must be greater than zero");
        Self {
            capacity,
            queue: Mutex::new(VecDeque::with_capacity(capacity)),
            not_empty: Condvar::new(),
            not_full: Condvar::new(),
        }
    }

    /// Push an item into the queue, blocking if full.
    pub fn push(&self, item: T) {
        let mut queue = self.queue.lock().unwrap();
        while queue.len() == self.capacity {
            // Wait until there is space
            queue = self.not_full.wait(queue).unwrap();
        }
        queue.push_back(item);
        // Notify a waiting popper
        self.not_empty.notify_one();
    }

    /// Pop an item from the queue, blocking if empty.
    pub fn pop(&self) -> T {
        let mut queue = self.queue.lock().unwrap();
        while queue.is_empty() {
            // Wait until there is an item
            queue = self.not_empty.wait(queue).unwrap();
        }
        let item = queue.pop_front().unwrap();
        // Notify a waiting pusher
        self.not_full.notify_one();
        item
    }

    /// Returns the current number of items in the queue.
    pub fn len(&self) -> usize {
        let queue = self.queue.lock().unwrap();
        queue.len()
    }
}

// Example usage:
fn main() {
    let queue = Arc::new(BoundedBlockingQueue::new(5));

    // Producer threads
    let producers: Vec<_> = (0..3).map(|i| {
        let queue = Arc::clone(&queue);
        thread::spawn(move || {
            for n in 0..10 {
                println!("Producer {} pushing {}", i, n);
                queue.push(format!("p{}-{}", i, n));
                thread::sleep(Duration::from_millis(50));
            }
        })
    }).collect();

    // Consumer threads
    let consumers: Vec<_> = (0..2).map(|i| {
        let queue = Arc::clone(&queue);
        thread::spawn(move || {
            for _ in 0..15 {
                let item = queue.pop();
                println!("Consumer {} got {}", i, item);
                thread::sleep(Duration::from_millis(120));
            }
        })
    }).collect();

    // Wait for all threads to finish
    for p in producers { p.join().unwrap(); }
    for c in consumers { c.join().unwrap(); }
}
```

---

### Notes

- The queue blocks on `.push()` if full, and on `.pop()` if empty.
- The queue is thread-safe.
- The example in `main` demonstrates multiple producers and consumers.
- You can adapt or extend this with `try_push`/`try_pop`, timeouts, etc. if needed.

