Certainly! Here is a complete, working Rust implementation of an arithmetic expression evaluator. This code allows you to input a string such as `"2 + 3 * (4 - 1)"` and evaluates it, supporting `+`, `-`, `*`, `/`, parentheses, whitespace, and integer (and floating-point) numbers.

```rust
use std::iter::Peekable;
use std::str::Chars;

#[derive(Debug, Clone, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Mul,
    Div,
    LParen,
    RParen,
}

fn tokenize(expr: &str) -> Result<Vec<Token>, String> {
    let mut tokens = Vec::new();
    let mut chars = expr.chars().peekable();

    while let Some(&ch) = chars.peek() {
        match ch {
            ' ' | '\t' | '\n' => { chars.next(); }
            '0'..='9' | '.' => {
                let mut number = String::new();
                while let Some(&c) = chars.peek() {
                    if c.is_digit(10) || c == '.' {
                        number.push(c);
                        chars.next();
                    } else {
                        break;
                    }
                }
                let value = number.parse().map_err(|_| format!("Invalid number: {}", number))?;
                tokens.push(Token::Number(value));
            }
            '+' => { tokens.push(Token::Plus); chars.next(); }
            '-' => { tokens.push(Token::Minus); chars.next(); }
            '*' => { tokens.push(Token::Mul); chars.next(); }
            '/' => { tokens.push(Token::Div); chars.next(); }
            '(' => { tokens.push(Token::LParen); chars.next(); }
            ')' => { tokens.push(Token::RParen); chars.next(); }
            other => return Err(format!("Unknown character: {}", other)),
        }
    }
    Ok(tokens)
}

// Recursive descent parser
struct Parser<I: Iterator<Item = Token>> {
    tokens: Peekable<I>,
}

impl<I: Iterator<Item = Token>> Parser<I> {
    fn new(iter: I) -> Self {
        Parser { tokens: iter.peekable() }
    }

    fn parse_expr(&mut self) -> Result<f64, String> {
        let mut result = self.parse_term()?;
        while let Some(op) = self.tokens.peek() {
            match op {
                Token::Plus => { self.tokens.next(); result += self.parse_term()?; }
                Token::Minus => { self.tokens.next(); result -= self.parse_term()?; }
                _ => break,
            }
        }
        Ok(result)
    }

    fn parse_term(&mut self) -> Result<f64, String> {
        let mut result = self.parse_factor()?;
        while let Some(op) = self.tokens.peek() {
            match op {
                Token::Mul => { self.tokens.next(); result *= self.parse_factor()?; }
                Token::Div => { 
                    self.tokens.next(); 
                    let divisor = self.parse_factor()?;
                    if divisor == 0.0 {
                        return Err("Division by zero".into());
                    }
                    result /= divisor;
                }
                _ => break,
            }
        }
        Ok(result)
    }

    fn parse_factor(&mut self) -> Result<f64, String> {
        match self.tokens.peek() {
            Some(Token::Minus) => {
                self.tokens.next();
                Ok(-self.parse_factor()?)
            }
            Some(Token::Plus) => {
                self.tokens.next();
                Ok(self.parse_factor()?)
            }
            Some(Token::Number(_)) | Some(Token::LParen) => self.parse_atom(),
            Some(token) => Err(format!("Unexpected token: {:?}", token)),
            None => Err("Unexpected end of input".to_string()),
        }
    }

    fn parse_atom(&mut self) -> Result<f64, String> {
        match self.tokens.next() {
            Some(Token::Number(n)) => Ok(n),
            Some(Token::LParen) => {
                let result = self.parse_expr()?;
                match self.tokens.next() {
                    Some(Token::RParen) => Ok(result),
                    other => Err(format!("Expected ')', found {:?}", other)),
                }
            }
            Some(other) => Err(format!("Unexpected token: {:?}", other)),
            None => Err("Unexpected end of input".to_string()),
        }
    }
}

pub fn eval_expression(expr: &str) -> Result<f64, String> {
    let tokens = tokenize(expr)?;
    let mut parser = Parser::new(tokens.into_iter());
    let result = parser.parse_expr()?;
    if parser.tokens.peek().is_some() {
        return Err("Unexpected trailing input".to_string());
    }
    Ok(result)
}

// Demonstration
fn main() {
    let exprs = [
        "2 + 3 * (4 - 1)",
        "1 + 2 * 3",
        "10 / 2 + 1",
        "(1 + 2) * (3 + 4)",
        "-5 + 4",
        "+3 * 2",
        "1 / 0",
        "3.14159 * 2",
    ];
    for expr in &exprs {
        match eval_expression(expr) {
            Ok(val) => println!("{} = {}", expr, val),
            Err(e) => println!("Error in '{}': {}", expr, e),
        }
    }
}
```

### How it works
- **Tokenization:** Converts the input string into tokens: numbers, operators, parentheses.
- **Parsing:** Using recursive descent, it respects operator precedence and supports parentheses and unary `+`/`-`.
- **Evaluation:** Combines token parsing with direct evaluation in the recursive methods.
- **Demo in main:** Evaluates a series of example expressions, printing the results.

