Certainly! Below is a basic regex matcher in Rust. This code supports the fundamental elements:

- Literal characters (e.g., `a`, `b`, ...)
- Dot (`.`) to match any character
- Star (`*`) for zero or more repetitions of the previous element

It's a simplified engine (without character classes, parentheses, etc.), but it should demonstrate the core ideas behind regex matching.

```rust
use std::env;

fn is_match(pattern: &str, text: &str) -> bool {
    is_match_helper(pattern.as_bytes(), text.as_bytes())
}

fn is_match_helper(pat: &[u8], text: &[u8]) -> bool {
    // If pattern is empty, text must be empty
    if pat.is_empty() {
        return text.is_empty();
    }

    // Check if the first char matches
    let first_match = (!text.is_empty()) &&
        (pat[0] == b'.' || pat[0] == text[0]);

    // Handle '*' for zero or more of the previous element
    if pat.len() >= 2 && pat[1] == b'*' {
        // Two possibilities:
        // 1. Skip the x* in pattern
        // 2. If first matches, move text only
        is_match_helper(&pat[2..], text)
            || (first_match && is_match_helper(pat, &text[1..]))
    } else {
        // Normal: move both
        first_match && is_match_helper(&pat[1..], &text[1..])
    }
}

fn main() {
    // Example usage: cargo run -- "a.*b" "axxxb"
    let args: Vec<String> = env::args().collect();
    if args.len() != 3 {
        println!("Usage: {} <pattern> <text>", args[0]);
        return;
    }

    let pattern = &args[1];
    let text = &args[2];

    println!(
        "Pattern: '{}'; Text: '{}'; Match: {}",
        pattern,
        text,
        is_match(pattern, text)
    );
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_simple() {
        assert!(is_match("abc", "abc"));
        assert!(!is_match("abc", "abd"));
        assert!(!is_match("abc", "ab"));
        assert!(!is_match("abc", "abcd"));
    }

    #[test]
    fn test_dot() {
        assert!(is_match("a.c", "abc"));
        assert!(is_match("a.c", "aoc"));
        assert!(!is_match("a.c", "ac"));
    }

    #[test]
    fn test_star() {
        assert!(is_match("ab*c", "ac"));
        assert!(is_match("ab*c", "abc"));
        assert!(is_match("ab*c", "abbbbbc"));
        assert!(!is_match("ab*c", "abbbbd"));
    }

    #[test]
    fn test_dot_star() {
        assert!(is_match("a.*c", "abc"));
        assert!(is_match("a.*c", "axyzc"));
        assert!(!is_match("a.*c", "abcd"));
    }

    #[test]
    fn test_star_zero() {
        assert!(is_match("a*b", "b"));
        assert!(is_match("a*b", "aaab"));
    }
}
```

**How it works:**

- `is_match(pattern, text)` is the entry point.
- It checks character-by-character: 
  - `.` matches any character.
  - `*` after a character (e.g. `a*`) matches zero or more of the preceding character.
- Recursive helper deals with the two main cases for `*`.
- Includes basic tests—run with `cargo test`.

