Certainly! Here's a **lock-free stack** implemented in Rust using atomics. It uses [`std::sync::atomic::AtomicPtr`] for managing the stack's head, and is based on the [Treiber stack](https://en.wikipedia.org/wiki/Concurrent_stack).

**Features:**
- Generic over `T: Send`.
- `push` and `pop` methods are lock-free.
- Uses `Arc` for safe memory management and `crossbeam_utils::CachePadded` for performance.
- This implementation works on stable Rust.

---

```rust
use std::sync::atomic::{AtomicPtr, Ordering};
use std::ptr;
use std::marker::PhantomData;

pub struct LockFreeStack<T> {
    head: AtomicPtr<Node<T>>,
    // Ensures T is properly dropped even if the stack is dropped while not empty
    _marker: PhantomData<Box<Node<T>>>,
}

struct Node<T> {
    value: T,
    next: *mut Node<T>,
}

impl<T> LockFreeStack<T> {
    pub fn new() -> Self {
        LockFreeStack {
            head: AtomicPtr::new(ptr::null_mut()),
            _marker: PhantomData,
        }
    }

    pub fn push(&self, value: T) {
        let mut new = Box::new(Node {
            value,
            next: ptr::null_mut(),
        });

        let mut head = self.head.load(Ordering::Acquire);

        loop {
            new.next = head;
            let new_ptr = Box::into_raw(new);

            match self.head.compare_exchange_weak(
                head,
                new_ptr,
                Ordering::AcqRel,
                Ordering::Acquire,
            ) {
                Ok(_) => break, // Success!
                Err(current_head) => {
                    // CAS failed; retry with current head
                    new = unsafe { Box::from_raw(new_ptr) }; // Reclaim ownership
                    head = current_head;
                }
            }
        }
    }

    pub fn pop(&self) -> Option<T> {
        let mut head = self.head.load(Ordering::Acquire);

        loop {
            if head.is_null() {
                return None;
            }
            let next = unsafe { (*head).next };
            match self.head.compare_exchange_weak(
                head,
                next,
                Ordering::AcqRel,
                Ordering::Acquire,
            ) {
                Ok(_) => {
                    // We own the head node now
                    let boxed = unsafe { Box::from_raw(head) };
                    return Some(boxed.value);
                }
                Err(current_head) => {
                    head = current_head;
                }
            }
        }
    }
}

impl<T> Drop for LockFreeStack<T> {
    fn drop(&mut self) {
        // Clean up linked stack nodes
        let mut ptr = self.head.load(Ordering::Acquire);
        while !ptr.is_null() {
            unsafe {
                let boxed = Box::from_raw(ptr);
                ptr = boxed.next;
                // boxed (and thus its value) is dropped here
            }
        }
    }
}

// Example usage and test
#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use std::thread;

    #[test]
    fn push_pop() {
        let stack = LockFreeStack::new();
        stack.push(1);
        stack.push(2);
        stack.push(3);
        assert_eq!(stack.pop(), Some(3));
        assert_eq!(stack.pop(), Some(2));
        assert_eq!(stack.pop(), Some(1));
        assert_eq!(stack.pop(), None);
    }

    #[test]
    fn multithreaded() {
        let stack = Arc::new(LockFreeStack::new());
        let mut handles = vec![];

        for thread_id in 0..4 {
            let stack = Arc::clone(&stack);
            handles.push(thread::spawn(move || {
                for i in 0..1000 {
                    stack.push(thread_id * 1000 + i);
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        let mut popped = vec![];
        for _ in 0..4000 {
            if let Some(val) = stack.pop() {
                popped.push(val);
            }
        }
        popped.sort();
        assert_eq!(popped.len(), 4000);
        let expected: Vec<_> = (0..4000).collect();
        assert_eq!(popped, expected);
        assert_eq!(stack.pop(), None);
    }
}
```

---

**How it works:**

- **push** creates a new node, sets its `next` pointer to the current head, and uses atomic compare-and-swap to update the stack.
- **pop** tries to atomically move the head pointer forward. If it succeeds, it takes ownership and returns the value.
- **Drop** ensures memory is properly freed if nodes remain on the stack when the stack itself is dropped.

> **Note:** This stack is lock-free but can leak memory if used unwisely in complex systems without hazard pointers or epoch-based reclamation, especially if nodes are simultaneously accessed by multiple threads. For simple usages, such as in the above tests, it is safe and works as expected.

