Certainly! Below is a complete working implementation of a **B-tree** in Rust, suitable for **learning and experimentation**. This implementation uses a generic key type `K` that implements the `Ord` and `Clone` traits, and a generic value type `V` that implements `Clone`. The B-tree order (minimum degree) is configurable.

Features:
- **Insertion**
- **Search**
- (No deletion for brevity, but can be extended.)

```rust
use std::cmp::Ordering;
use std::fmt::Debug;

// Minimum degree of the B-tree (t >= 2)
const MIN_DEGREE: usize = 2;

#[derive(Debug, Clone)]
struct BTreeNode<K, V>
where
    K: Ord + Clone + Debug,
    V: Clone + Debug,
{
    keys: Vec<K>,
    values: Vec<V>,
    children: Vec<Box<BTreeNode<K, V>>>,
    leaf: bool,
}

impl<K, V> BTreeNode<K, V>
where
    K: Ord + Clone + Debug,
    V: Clone + Debug,
{
    fn new(leaf: bool) -> Self {
        BTreeNode {
            keys: Vec::new(),
            values: Vec::new(),
            children: Vec::new(),
            leaf,
        }
    }

    /// Search for a key in the subtree rooted with this node
    fn search(&self, key: &K) -> Option<&V> {
        let mut i = 0;
        while i < self.keys.len() && *key > self.keys[i] {
            i += 1;
        }
        if i < self.keys.len() && *key == self.keys[i] {
            Some(&self.values[i])
        } else if self.leaf {
            None
        } else {
            self.children[i].search(key)
        }
    }

    /// Insert a key into a non-full node
    fn insert_non_full(&mut self, key: K, value: V) {
        let mut i = self.keys.len();
        if self.leaf {
            // Find the position to insert
            while i > 0 && key < self.keys[i - 1] {
                i -= 1;
            }
            self.keys.insert(i, key);
            self.values.insert(i, value);
        } else {
            // Find the child to descend
            while i > 0 && key < self.keys[i - 1] {
                i -= 1;
            }
            // If child is full, split
            if self.children[i].keys.len() == 2 * MIN_DEGREE - 1 {
                self.split_child(i);
                if key > self.keys[i] {
                    i += 1;
                }
            }
            self.children[i].insert_non_full(key, value);
        }
    }

    /// Split the child of this node at index i
    fn split_child(&mut self, i: usize) {
        let mut y = self.children[i].as_mut();
        let mut z = Box::new(BTreeNode::new(y.leaf));
        // y is full with 2t-1 keys; move t-1 keys from y to z
        z.keys = y.keys.split_off(MIN_DEGREE);
        let mid_key = y.keys.pop().unwrap(); // this is the median key
        z.values = y.values.split_off(MIN_DEGREE);
        let mid_value = y.values.pop().unwrap();

        // If y is not a leaf, move the last t children to z
        if !y.leaf {
            z.children = y.children.split_off(MIN_DEGREE);
        }

        // Insert the middle key and value into self (the parent)
        self.keys.insert(i, mid_key);
        self.values.insert(i, mid_value);
        self.children.insert(i + 1, z);
    }

    /// Traverse and print keys for debug
    fn traverse(&self, depth: usize) {
        let indent = "  ".repeat(depth);
        for i in 0..self.keys.len() {
            if !self.leaf {
                self.children[i].traverse(depth + 1);
            }
            println!("{}Key: {:?} => {:?}", indent, self.keys[i], self.values[i]);
        }
        if !self.leaf {
            self.children[self.keys.len()].traverse(depth + 1);
        }
    }
}

#[derive(Debug, Clone)]
pub struct BTree<K, V>
where
    K: Ord + Clone + Debug,
    V: Clone + Debug,
{
    root: Box<BTreeNode<K, V>>,
}

impl<K, V> BTree<K, V>
where
    K: Ord + Clone + Debug,
    V: Clone + Debug,
{
    pub fn new() -> Self {
        BTree {
            root: Box::new(BTreeNode::new(true)),
        }
    }

    pub fn search(&self, key: &K) -> Option<&V> {
        self.root.search(key)
    }

    pub fn insert(&mut self, key: K, value: V) {
        if self.root.keys.len() == 2 * MIN_DEGREE - 1 {
            // Root is full, need to grow tree height
            let mut new_root = Box::new(BTreeNode::new(false));
            new_root.children.push(self.root.clone());
            new_root.split_child(0);
            new_root.insert_non_full(key, value);
            self.root = new_root;
        } else {
            self.root.insert_non_full(key, value);
        }
    }

    /// Traverse the tree (debug)
    pub fn traverse(&self) {
        self.root.traverse(0);
    }
}

fn main() {
    let mut btree = BTree::<i32, &str>::new();

    let entries = vec![
        (10, "a"),
        (20, "b"),
        (5, "c"),
        (6, "d"),
        (12, "e"),
        (30, "f"),
        (7, "g"),
        (17, "h"),
    ];

    for (k, v) in &entries {
        btree.insert(*k, *v);
    }

    println!("Traverse the B-tree:");
    btree.traverse();

    println!("\nSearch:");
    for k in [6, 15, 17, 30, 100] {
        match btree.search(&k) {
            Some(v) => println!("Key {} -> {}", k, v),
            None => println!("Key {} not found", k),
        }
    }
}
```

