Certainly! Below is a **minimal working implementation of the Raft leader election protocol in Rust**, using threads and channels to simulate a cluster of Raft nodes communicating via message passing. This does **not** include log replication, persistence, or a real network, but accurately reflects leader election, including election timeouts, request/reply, and randomized timeouts to prevent split votes.

To keep things straightforward:
- Each node runs in its own thread.
- Communication is via `std::sync::mpsc` channels inside the same process.
- The cluster size is fixed and hardcoded (~3 or 5).
- The code includes comments for clarity.

---

```rust
use rand::{thread_rng, Rng};
use std::{
    collections::HashMap,
    sync::mpsc::{self, Receiver, Sender},
    thread,
    time::{Duration, Instant},
};

#[derive(Clone, Debug)]
enum Message {
    RequestVote {
        term: u64,
        candidate_id: usize,
    },
    RequestVoteReply {
        term: u64,
        vote_granted: bool,
        from: usize,
    },
    // For demonstration, heartbeat is optional
    Heartbeat {
        term: u64,
        leader_id: usize,
    },
}

#[derive(Debug, PartialEq, Eq)]
enum State {
    Follower,
    Candidate,
    Leader,
}

struct RaftNode {
    id: usize,
    peers: Vec<Sender<(usize, Message)>>, // All senders, including self for convenience
    recv: Receiver<Message>,

    current_term: u64,
    voted_for: Option<usize>,
    state: State,
}

const NUM_NODES: usize = 3;

impl RaftNode {
    fn new(
        id: usize,
        peers: Vec<Sender<(usize, Message)>>,
        recv: Receiver<Message>,
    ) -> Self {
        RaftNode {
            id,
            peers,
            recv,
            current_term: 0,
            voted_for: None,
            state: State::Follower,
        }
    }

    fn run(mut self) {
        let mut rng = thread_rng();
        let mut election_deadline = Instant::now()
            + Duration::from_millis(rng.gen_range(150..400));

        let mut votes_received: usize = 0;

        loop {
            // For heartbeat/leader, send heartbeats
            if self.state == State::Leader {
                for (peer_id, tx) in self.peers.iter().enumerate() {
                    if peer_id == self.id {
                        continue;
                    }
                    let msg = Message::Heartbeat {
                        term: self.current_term,
                        leader_id: self.id,
                    };
                    let _ = tx.send((self.id, msg));
                }
                thread::sleep(Duration::from_millis(50));
                continue;
            }

            // Follower or Candidate: wait for messages or timeout
            let timeout = election_deadline
                .saturating_duration_since(Instant::now());
            let msg = self.recv.recv_timeout(timeout);

            match msg {
                Ok(Message::RequestVote { term, candidate_id }) => {
                    if term > self.current_term {
                        self.current_term = term;
                        self.voted_for = None;
                        self.state = State::Follower;
                    }
                    let mut vote_granted = false;
                    if term == self.current_term &&
                        (self.voted_for.is_none() || self.voted_for == Some(candidate_id))
                    {
                        self.voted_for = Some(candidate_id);
                        vote_granted = true;
                        // Grant, and reset election timer
                        election_deadline =
                            Instant::now() + Duration::from_millis(rng.gen_range(150..400));
                    }
                    // Reply
                    let reply = Message::RequestVoteReply {
                        term: self.current_term,
                        vote_granted,
                        from: self.id,
                    };
                    let _ = self.peers[candidate_id].send((self.id, reply));
                }
                Ok(Message::RequestVoteReply { term, vote_granted, from }) => {
                    if self.state != State::Candidate {
                        continue;
                    }
                    if term > self.current_term {
                        self.current_term = term;
                        self.state = State::Follower;
                        self.voted_for = None;
                        continue;
                    }
                    if term == self.current_term && vote_granted {
                        votes_received += 1;
                        let majority = NUM_NODES / 2 + 1;
                        if votes_received >= majority {
                            println!("[Node {}] is elected as Leader for term {}", self.id, self.current_term);
                            self.state = State::Leader;
                            // On election: send heartbeats soon
                        }
                    }
                }
                Ok(Message::Heartbeat { term, leader_id }) => {
                    if term > self.current_term {
                        self.current_term = term;
                        self.state = State::Follower;
                        self.voted_for = None;
                        //println!("[Node {}] term updated to {}, new leader {}", self.id, term, leader_id);
                    }
                    if term == self.current_term {
                        self.state = State::Follower;
                        election_deadline =
                            Instant::now() + Duration::from_millis(rng.gen_range(150..400));
                    }
                    // Else ignore stale heartbeat
                }
                Err(mpsc::RecvTimeoutError::Timeout) => {
                    // Election timeout -- start election
                    self.current_term += 1;
                    self.state = State::Candidate;
                    self.voted_for = Some(self.id);
                    votes_received = 1; // voted for self

                    println!("[Node {}] starts election for term {}", self.id, self.current_term);

                    // Broadcast RequestVote
                    let msg = Message::RequestVote {
                        term: self.current_term,
                        candidate_id: self.id,
                    };
                    for (peer_id, tx) in self.peers.iter().enumerate() {
                        if peer_id == self.id {
                            continue;
                        }
                        let _ = tx.send((self.id, msg.clone()));
                    }
                    // Reset election_deadline for next round
                    election_deadline =
                        Instant::now() + Duration::from_millis(rng.gen_range(150..400));
                }
                Err(mpsc::RecvTimeoutError::Disconnected) => {
                    break; // exits if communication is lost
                }
            }
        }
    }
}

