    // Spawn nodes
    for id in 0..NUM_NODES {
        let my_rx = rxs.remove(0);

        // Clone one sender to net
        let my_net_tx = net_tx.clone();

        // Each node gets a vector of "net_tx" + it's own id to specify "to"
        let peers: Vec<Sender<(usize, Message)>> = (0..NUM_NODES)
            .map(|peer_id| {
                let tx = net_tx.clone();
                let peer_sender = move |from: usize, msg: Message| -> Result<(), mpsc::SendError<(usize, Message)>> {
                    tx.send((peer_id, from, msg)).map_err(|e| mpsc::SendError((from, msg)))
                };
                // Wrap in a Sender-like
                SenderProxy { peer_id, from_id: id, net_tx: tx.clone() }.into_sender()
            })
            .collect();

        // Now, each node runs in its own thread
        let node = RaftNode::new(id, peers, my_rx);
        handles.push(thread::spawn(move || node.run()));
    }

    // The "network" thread
    let network_mailboxes: HashMap<usize, Sender<Message>> = mailboxes.clone();
    thread::spawn(move || {
        for (to, _from, msg) in net_rx {
            if let Some(tx) = network_mailboxes.get(&to) {
                let _ = tx.send(msg);
            }
        }
    });

    // Let the cluster run for a while
    thread::sleep(Duration::from_secs(10));
    // The nodes will naturally exit if mpsc channels are closed.

    println!("Done.");
}

// Helper for the makeshift network: a "Sender"-like
struct SenderProxy {
    peer_id: usize,
    from_id: usize,
    net_tx: Sender<(usize, usize, Message)>,
}

impl SenderProxy {
    fn into_sender(self) -> Sender<(usize, Message)> {
        let (tx, rx) = mpsc::channel::<(usize, Message)>();
        let net_tx = self.net_tx.clone();
        let peer_id = self.peer_id;
        thread::spawn(move || {
            for (from, msg) in rx {
                let _ = net_tx.send((peer_id, from, msg));
            }
        });
        tx
    }
}
