Certainly! Below is a complete, working **persistent (immutable) red-black tree** implementation in Rust. This design is functional: updates return new versions of the tree, sharing unchanged structure (making it *persistent*). It supports insertion and lookup. Deletion is more involved but can be added similarly.

The tree is generic over key and value (requires `Ord` for keys and `Clone` for both K and V).

---

```rust
use std::rc::Rc;
use std::fmt::{self, Debug};

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Color {
    Red,
    Black,
}

use Color::*;

type TreeLink<K, V> = Option<Rc<Node<K, V>>>;

#[derive(Clone)]
struct Node<K: Ord + Clone, V: Clone> {
    color: Color,
    key: K,
    value: V,
    left: TreeLink<K, V>,
    right: TreeLink<K, V>,
}

pub struct RBTree<K: Ord + Clone, V: Clone> {
    root: TreeLink<K, V>,
}

impl<K: Ord + Clone, V: Clone> RBTree<K, V> {
    pub fn new() -> Self {
        RBTree { root: None }
    }

    pub fn get(&self, key: &K) -> Option<V> {
        let mut cur = self.root.clone();
        while let Some(node) = cur {
            if *key < node.key {
                cur = node.left.clone();
            } else if *key > node.key {
                cur = node.right.clone();
            } else {
                return Some(node.value.clone());
            }
        }
        None
    }

    pub fn insert(&self, key: K, value: V) -> Self {
        let root = Self::ins(self.root.clone(), key, value);
        // The root must always be black
        RBTree {
            root: Some(Rc::new(Node {
                color: Black,
                ..(*root.unwrap()).clone()
            })),
        }
    }

    // Internal insert function
    fn ins(tree: TreeLink<K, V>, key: K, value: V) -> TreeLink<K, V> {
        match tree {
            None => {
                Some(Rc::new(Node {
                    color: Red,
                    key,
                    value,
                    left: None,
                    right: None,
                }))
            }
            Some(node) => {
                if key < node.key {
                    let left = Self::ins(node.left.clone(), key, value);
                    Self::balance(node.color, left, node.key.clone(), node.value.clone(), node.right.clone())
                } else if key > node.key {
                    let right = Self::ins(node.right.clone(), key, value);
                    Self::balance(node.color, node.left.clone(), node.key.clone(), node.value.clone(), right)
                } else {
                    // Replace value
                    Some(Rc::new(Node {
                        color: node.color,
                        key,
                        value,
                        left: node.left.clone(),
                        right: node.right.clone(),
                    }))
                }
            }
        }
    }

    // Balancing after insert, following Okasaki's paper
    fn balance(
        color: Color,
        left: TreeLink<K, V>,
        key: K,
        value: V,
        right: TreeLink<K, V>,
    ) -> TreeLink<K, V> {
        // Left-Left Red violation
        if color == Black
            && is_red(&left)
            && is_red(&left.as_ref().unwrap().left)
        {
            let l = left.unwrap();
            let ll = l.left.as_ref().unwrap();
            return Some(Rc::new(Node {
                color: Red,
                key: l.key.clone(),
                value: l.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: ll.key.clone(),
                    value: ll.value.clone(),
                    left: ll.left.clone(),
                    right: ll.right.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key,
                    value,
                    left: l.right.clone(),
                    right,
                }))
            }));
        }

        // Left-Right Red violation
        if color == Black
            && is_red(&left)
            && is_red(&left.as_ref().unwrap().right)
        {
            let l = left.unwrap();
            let lr = l.right.as_ref().unwrap();
            return Some(Rc::new(Node {
                color: Red,
                key: lr.key.clone(),
                value: lr.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: l.key.clone(),
                    value: l.value.clone(),
                    left: l.left.clone(),
                    right: lr.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key,
                    value,
                    left: lr.right.clone(),
                    right,
                })),
            }));
        }

        // Right-Left Red violation
        if color == Black
            && is_red(&right)
            && is_red(&right.as_ref().unwrap().left)
        {
            let r = right.unwrap();
            let rl = r.left.as_ref().unwrap();
            return Some(Rc::new(Node {
                color: Red,
                key: rl.key.clone(),
                value: rl.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key,
                    value,
                    left,
                    right: rl.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: r.key.clone(),
                    value: r.value.clone(),
                    left: rl.right.clone(),
                    right: r.right.clone(),
                })),
            }));
        }

        // Right-Right Red violation
        if color == Black
            && is_red(&right)
            && is_red(&right.as_ref().unwrap().right)
        {
            let r = right.unwrap();
            let rr = r.right.as_ref().unwrap();
            return Some(Rc::new(Node {
                color: Red,
                key: r.key.clone(),
                value: r.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key,
                    value,
                    left,
                    right: r.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: rr.key.clone(),
                    value: rr.value.clone(),
                    left: rr.left.clone(),
                    right: rr.right.clone(),
                })),
            }));
        }

        Some(Rc::new(Node {
            color,
            key,
            value,
            left,
            right,
        }))
    }

    /// For testing - in-order collection
    pub fn to_vec(&self) -> Vec<(K, V)> {
        let mut v = Vec::new();
        Self::inorder(&self.root, &mut v);
        v
    }

    fn inorder(tree: &TreeLink<K, V>, vec: &mut Vec<(K, V)>) {
        if let Some(node) = tree {
            Self::inorder(&node.left, vec);
            vec.push((node.key.clone(), node.value.clone()));
            Self::inorder(&node.right, vec);
        }
    }
}

// Helper
fn is_red<K: Ord + Clone, V: Clone>(node: &TreeLink<K, V>) -> bool {
    node.as_ref().map_or(false, |n| n.color == Red)
}

// Debug output for tree structure
impl<K: Ord + Clone + Debug, V: Clone + Debug> Debug for RBTree<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        fn fmt_node<K: Debug, V: Debug>(
            node: &TreeLink<K, V>,
            f: &mut fmt::Formatter<'_>,
            prefix: String,
            is_left: bool,
        ) -> fmt::Result {
            if let Some(node) = node {
                writeln!(
                    f,
                    "{}{}─ {:?}:{:?} ({:?})",
                    prefix,
                    if is_left { "├" } else { "└" },
                    node.key,
                    node.value,
                    node.color
                )?;
                let next_prefix = format!("{}{}", prefix, if is_left { "│ " } else { "  " });
                fmt_node(&node.left, f, next_prefix.clone(), true)?;
                fmt_node(&node.right, f, next_prefix, false)?;
            }
            Ok(())
        }

        fmt_node(&self.root, f, "".to_string(), false)
    }
}

// Example and test
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_insert_and_get() {
        let t = RBTree::new();
        let t1 = t.insert(3, "a");
        let t2 = t1.insert(1, "b");
        let t3 = t2.insert(4, "c");
        let t4 = t3.insert(5, "d");
        let t5 = t4.insert(9, "e");
        let t6 = t5.insert(2, "f");

        assert_eq!(t6.get(&3), Some("a"));
        assert_eq!(t6.get(&1), Some("b"));
        assert_eq!(t6.get(&4), Some("c"));
        assert_eq!(t6.get(&5), Some("d"));
        assert_eq!(t6.get(&9), Some("e"));
        assert_eq!(t6.get(&2), Some("f"));
        assert_eq!(t6.get(&0), None);

        // `t` is still the empty tree
        assert_eq!(t.get(&3), None);

        // In-order traversal
        assert_eq!(
            t6.to_vec(),
            vec![(1, "b"), (2, "f"), (3, "a"), (4, "c"), (5, "d"), (9, "e")]
        );

        // Persistent: earlier version is unchanged
        assert_eq!(t5.get(&2), None);
    }
}
```

