Here's a **complete, standalone skip list implementation in Rust**. The skip list supports insertion, search, and removal of elements for generic types that implement `Ord + Clone`. This example uses randomization for level heights, offers means to specify the maximum level, and demonstrates usage with a simple integer skip list at the bottom.

```rust
use rand::prelude::*;
use std::cmp::Ordering;
use std::ptr::NonNull;
use std::fmt::{self, Debug};

const MAX_LEVEL: usize = 16;
const P: f64 = 0.5; // Probability for level increases

#[derive(Clone)]
struct Node<T> {
    value: Option<T>,
    forwards: Vec<Option<NonNull<Node<T>>>>,
}

impl<T: Debug> Debug for Node<T> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("Node")
        .field("value", &self.value)
        .finish()
    }
}

pub struct SkipList<T> {
    head: Box<Node<T>>,
    level: usize,
    len: usize,
}

impl<T: Ord + Clone> SkipList<T> {
    pub fn new() -> Self {
        Self {
            head: Box::new(Node {
                value: None,
                forwards: vec![None; MAX_LEVEL],
            }),
            level: 1,
            len: 0,
        }
    }

    fn random_level() -> usize {
        let mut lvl = 1;
        let mut rng = thread_rng();
        while rng.gen::<f64>() < P && lvl < MAX_LEVEL {
            lvl += 1;
        }
        lvl
    }

    pub fn contains(&self, value: &T) -> bool {
        let mut curr: *const Node<T> = &*self.head;
        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*curr).forwards[i] {
                    if let Some(ref next_val) = (*next.as_ptr()).value {
                        match next_val.cmp(value) {
                            Ordering::Less => curr = next.as_ptr(),
                            Ordering::Equal => return true,
                            Ordering::Greater => break,
                        }
                    }
                }
            }
            if let Some(Some(next)) = (*curr).forwards.get(0) {
                if let Some(ref next_val) = (*next.as_ptr()).value {
                    next_val == value
                } else {
                    false
                }
            } else {
                false
            }
        }
    }

    pub fn insert(&mut self, value: T) -> bool {
        let mut update: Vec<*mut Node<T>> = vec![std::ptr::null_mut(); MAX_LEVEL];
        let mut curr: *mut Node<T> = &mut *self.head;

        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*curr).forwards[i] {
                    if let Some(ref next_val) = (*next.as_ptr()).value {
                        if *next_val < value {
                            curr = next.as_ptr();
                        } else {
                            break;
                        }
                    }
                }
                update[i] = curr;
            }

            // Check for duplicate
            if let Some(Some(next)) = (*curr).forwards.get(0) {
                if let Some(ref next_val) = (*next.as_ptr()).value {
                    if *next_val == value {
                        return false; // already exists
                    }
                }
            }

            let lvl = Self::random_level();
            if lvl > self.level {
                for i in self.level..lvl {
                    update[i] = &mut *self.head;
                }
                self.level = lvl;
            }
            let mut new_node = Box::new(Node {
                value: Some(value),
                forwards: vec![None; lvl],
            });
            let new_ptr = NonNull::new(Box::into_raw(new_node)).unwrap();
            for i in 0..lvl {
                let prev = update[i];
                (*new_ptr.as_ptr()).forwards[i] = (*prev).forwards[i];
                (*prev).forwards[i] = Some(new_ptr);
            }
            self.len += 1;
            true
        }
    }

    pub fn remove(&mut self, value: &T) -> bool {
        let mut update: Vec<*mut Node<T>> = vec![std::ptr::null_mut(); MAX_LEVEL];
        let mut curr: *mut Node<T> = &mut *self.head;
        let mut found = false;

        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*curr).forwards[i] {
                    if let Some(ref next_val) = (*next.as_ptr()).value {
                        if *next_val < *value {
                            curr = next.as_ptr();
                        } else {
                            break;
                        }
                    }
                }
                update[i] = curr;
            }
            if let Some(Some(next)) = (*curr).forwards.get(0) {
                if let Some(ref next_val) = (*next.as_ptr()).value {
                    if *next_val == *value {
                        found = true;
                        let target = next;
                        for i in 0..self.level {
                            if let Some(fwd) = (*update[i]).forwards[i] {
                                if fwd == target {
                                    (*update[i]).forwards[i] = (*fwd.as_ptr()).forwards[i];
                                }
                            }
                        }
                        let _ = Box::from_raw(target.as_ptr()); // drop
                        while self.level > 1 && self.head.forwards[self.level - 1].is_none() {
                            self.level -= 1;
                        }
                        self.len -= 1;
                    }
                }
            }
        }
        found
    }

    pub fn len(&self) -> usize {
        self.len
    }
}

// Iterator support for SkipList
pub struct SkipListIter<'a, T> {
    next: Option<NonNull<Node<T>>>,
    phantom: std::marker::PhantomData<&'a T>,
}

impl<T: Ord + Clone> SkipList<T> {
    pub fn iter(&self) -> SkipListIter<'_, T> {
        let first = self.head.forwards[0];
        SkipListIter {
            next: first,
            phantom: std::marker::PhantomData,
        }
    }
}

impl<'a, T: Ord + Clone> Iterator for SkipListIter<'a, T> {
    type Item = &'a T;
    fn next(&mut self) -> Option<Self::Item> {
        match self.next {
            Some(node) => unsafe {
                let n = &*node.as_ptr();
                self.next = n.forwards[0];
                n.value.as_ref()
            }
            None => None,
        }
    }
}

// For demonstration:

fn main() {
    let mut sl = SkipList::new();

    println!("Insert 3: {}", sl.insert(3));
    println!("Insert 6: {}", sl.insert(6));
    println!("Insert 7: {}", sl.insert(7));
    println!("Insert 9: {}", sl.insert(9));
    println!("Insert 2: {}", sl.insert(2));
    println!("Insert 11: {}", sl.insert(11));
    println!("Insert 1: {}", sl.insert(1));
    println!("Insert 4: {}", sl.insert(4));
    println!("List len: {}", sl.len());

    println!("\nSkipList contains 6? {}", sl.contains(&6));
    println!("SkipList contains 10? {}", sl.contains(&10));
    println!("\nIterating skip list:");
    for value in sl.iter() {
        println!("{}", value);
    }

    println!("\nRemove 3: {}", sl.remove(&3));
    println!("Remove 100: {}", sl.remove(&100));

    println!("\nSkipList after removing 3:");
    for value in sl.iter() {
        println!("{}", value);
    }

    println!("List len: {}", sl.len());
}
```

**How this works:**

- `SkipList<T>` can store ordered, cloneable types.
- Contains insert, search, and remove operations.
- Random levels chosen for each inserted node.
- Uses unsafe code and raw pointers for performance and internal mutability (takes care NOT to create cycles/leaks).
- Has an iterator implementation.
- Demo in the `main()` function.

