use num_complex::Complex64;
use rand::distributions::{Distribution, WeightedIndex};
use rand::thread_rng;

fn kron(a: &[Complex64], b: &[Complex64]) -> Vec<Complex64> {
    a.iter().flat_map(|x| b.iter().map(move |y| x * y)).collect()
}

fn apply_gate(state: &mut [Complex64], gate: &[Complex64], target: usize, n: usize) {
    let mut new = vec![Complex64::new(0.0, 0.0); 1 << n];
    for i in 0..(1 << n) {
        let bit = (i >> target) & 1;
        for (j, &v) in gate.iter().enumerate().take(2) {
            let idx = (i & !(1 << target)) | ((j as usize) << target);
            new[i] += v * state[idx];
        }
    }
    state.copy_from_slice(&new);
}

fn apply_cnot(state: &mut [Complex64], c: usize, t: usize, n: usize) {
    for i in 0..(1 << n) {
        if ((i >> c) & 1) != 0 && ((i >> t) & 1) == 0 {
            let j = i | (1 << t);
            state.swap(i, j);
        }
    }
}

fn measure(state: &[Complex64]) -> usize {
    let probs: Vec<f64> = state.iter().map(|a| a.norm_sqr()).collect();
    let dist = WeightedIndex::new(&probs).unwrap();
    dist.sample(&mut thread_rng())
}

fn main() {
    let n = 2;
    let mut state = vec![Complex64::new(0.0, 0.0); 1 << n];
    state[0] = Complex64::new(1.0, 0.0);
    let h = [Complex64::new(1.0 / 2f64.sqrt(), 0.0); 2];
    let x = [Complex64::new(0.0, 0.0), Complex64::new(1.0, 0.0)];
    apply_gate(&mut state, &h, 0, n);      // H on qubit 0
    apply_cnot(&mut state, 0, 1, n);       // CNOT(0,1)
    let outcome = measure(&state);
    println!("Measured: {:0n$b}", outcome, n = n);
}
```

