Certainly! Here is a complete, working implementation of a generic stack in Rust. This version uses a `Vec<T>` for storage, as it's the most idiomatic and efficient way to implement a stack in Rust.

```rust
/// A generic stack data structure.
///
/// # Examples
///
/// ```
/// let mut stack = Stack::new();
/// stack.push(1);
/// stack.push(2);
/// assert_eq!(stack.pop(), Some(2));
/// assert_eq!(stack.pop(), Some(1));
/// assert_eq!(stack.pop(), None);
/// ```
pub struct Stack<T> {
    elements: Vec<T>,
}

impl<T> Stack<T> {
    /// Creates a new empty stack.
    pub fn new() -> Self {
        Stack { elements: Vec::new() }
    }

    /// Adds an element to the top of the stack.
    pub fn push(&mut self, item: T) {
        self.elements.push(item);
    }

    /// Removes the top element from the stack and returns it, or `None` if the stack is empty.
    pub fn pop(&mut self) -> Option<T> {
        self.elements.pop()
    }

    /// Returns a reference to the top element of the stack, or `None` if the stack is empty.
    pub fn peek(&self) -> Option<&T> {
        self.elements.last()
    }

    /// Returns `true` if the stack is empty.
    pub fn is_empty(&self) -> bool {
        self.elements.is_empty()
    }

    /// Returns the number of elements in the stack.
    pub fn len(&self) -> usize {
        self.elements.len()
    }
}

// Example usage
fn main() {
    let mut stack = Stack::new();

    stack.push(10);
    stack.push(20);
    stack.push(30);

    println!("Stack length: {}", stack.len()); // Output: 3

    while let Some(val) = stack.pop() {
        println!("Popped: {}", val);
    }
}
```

### How this works:

- `Stack<T>` uses a vector to store elements.
- `push()` adds to the end (the top of the stack).
- `pop()` removes from the end (the top).
- `peek()` checks the top element without removing it.
- `is_empty()` and `len()` provide additional utility.

### How to run

Place this in a single `.rs` file (e.g., `main.rs`) and run with `cargo run` or `rustc main.rs && ./main`.

