Sure! Below is a complete and working Rust implementation of an LRU (Least Recently Used) cache. This implementation is generic over key and value types and supports constant time operations (`O(1)`) for both `get` and `put` using a combination of a hash map and a doubly linked list.

```rust
use std::collections::HashMap;
use std::cell::{RefCell, RefMut};
use std::rc::{Rc, Weak};
use std::hash::Hash;

// Definition for a doubly linked list node
struct Node<K, V> {
    key: K,
    val: V,
    prev: Option<Weak<RefCell<Node<K, V>>>>,
    next: Option<Rc<RefCell<Node<K, V>>>>,
}

pub struct LRUCache<K, V> {
    map: HashMap<K, Rc<RefCell<Node<K, V>>>>,
    cap: usize,
    head: Option<Rc<RefCell<Node<K, V>>>>, // Most recently used
    tail: Option<Rc<RefCell<Node<K, V>>>>, // Least recently used
}

impl<K, V> LRUCache<K, V>
where
    K: Eq + Hash + Clone,
    V: Clone,
{
    pub fn new(capacity: usize) -> Self {
        Self {
            map: HashMap::new(),
            cap: capacity,
            head: None,
            tail: None,
        }
    }

    pub fn get(&mut self, key: &K) -> Option<V> {
        if let Some(node) = self.map.get(key).cloned() {
            self.move_to_head(node.clone());
            Some(node.borrow().val.clone())
        } else {
            None
        }
    }

    pub fn put(&mut self, key: K, value: V) {
        if let Some(node) = self.map.get(&key).cloned() {
            node.borrow_mut().val = value;
            self.move_to_head(node);
        } else {
            if self.map.len() == self.cap {
                self.pop_tail();
            }
            let node = Rc::new(RefCell::new(Node {
                key: key.clone(),
                val: value,
                prev: None,
                next: None,
            }));
            self.add_to_head(node.clone());
            self.map.insert(key, node);
        }
    }

    fn add_to_head(&mut self, node: Rc<RefCell<Node<K, V>>>) {
        node.borrow_mut().next = self.head.clone();
        node.borrow_mut().prev = None;

        if let Some(old_head) = self.head.take() {
            old_head.borrow_mut().prev = Some(Rc::downgrade(&node));
            self.head = Some(node);
        } else {
            // Empty list
            self.tail = Some(node.clone());
            self.head = Some(node);
        }
    }

    fn move_to_head(&mut self, node: Rc<RefCell<Node<K, V>>>) {
        // Already at head
        if let Some(ref head) = self.head {
            if Rc::ptr_eq(&node, head) {
                return;
            }
        }
        self.remove_node(node.clone());
        self.add_to_head(node);
    }

    fn remove_node(&mut self, node: Rc<RefCell<Node<K, V>>>) {
        let prev_opt = node.borrow_mut().prev.take();
        let next_opt = node.borrow_mut().next.take();

        if let Some(prev_weak) = prev_opt {
            if let Some(prev) = prev_weak.upgrade() {
                prev.borrow_mut().next = next_opt.clone();
            }
        } else {
            // node is head
            self.head = next_opt.clone();
        }

        if let Some(next) = next_opt {
            next.borrow_mut().prev = prev_opt;
        } else {
            // node is tail
            self.tail = prev_opt.and_then(|weak| weak.upgrade());
        }
    }

    fn pop_tail(&mut self) {
        if let Some(tail) = self.tail.take() {
            let key = tail.borrow().key.clone();
            self.remove_node(tail.clone());
            self.map.remove(&key);
        }
    }
}

// ========== Example Usage & Tests ==========
#[cfg(test)]
mod tests {
    use super::LRUCache;

    #[test]
    fn test_lru_cache() {
        let mut cache = LRUCache::new(2);
        cache.put(1, 10);
        cache.put(2, 20);
        assert_eq!(cache.get(&1), Some(10));
        cache.put(3, 30); // evicts key 2
        assert_eq!(cache.get(&2), None);
        cache.put(4, 40); // evicts key 1
        assert_eq!(cache.get(&1), None);
        assert_eq!(cache.get(&3), Some(30));
        assert_eq!(cache.get(&4), Some(40));
    }
}

fn main() {
    let mut cache = LRUCache::new(2);
    cache.put(1, "a");
    cache.put(2, "b");
    println!("{:?}", cache.get(&1)); // Some("a")
    cache.put(3, "c"); // evicts key 2
    println!("{:?}", cache.get(&2)); // None
    cache.put(4, "d"); // evicts key 1
    println!("{:?}", cache.get(&1)); // None
    println!("{:?}", cache.get(&3)); // Some("c")
    println!("{:?}", cache.get(&4)); // Some("d")
}
```

**How it works:**
- `LRUCache::get` moves an accessed item to the front (most recently used).
- `LRUCache::put` adds new items to the front and removes the least recently used if full.
- Internally, it uses a doubly linked list for tracking item usage order and a hash map for fast lookup.

**Test & Example Usage:**
- Includes `#[cfg(test)]` with a basic test.
- The `main()` function demonstrates how to use the cache.

