## 1. TreeNode definition

```rust
use std::rc::Rc;
use std::cell::RefCell;

// Basic TreeNode for binary tree.
#[derive(Debug, PartialEq, Eq)]
pub struct TreeNode {
    pub val: i32,
    pub left: Option<Rc<RefCell<TreeNode>>>,
    pub right: Option<Rc<RefCell<TreeNode>>>,
}

impl TreeNode {
    #[inline]
    pub fn new(val: i32) -> Self {
        TreeNode { val, left: None, right: None }
    }
}
```

## 2. Codec struct and impl

```rust
pub struct Codec;

impl Codec {
    pub fn new() -> Self {
        Codec
    }

    // Serializes a tree to a single string.
    pub fn serialize(&self, root: Option<Rc<RefCell<TreeNode>>>) -> String {
        fn helper(node: &Option<Rc<RefCell<TreeNode>>>, out: &mut Vec<String>) {
            if let Some(n) = node {
                let n = n.borrow();
                out.push(n.val.to_string());
                helper(&n.left, out);
                helper(&n.right, out);
            } else {
                out.push("null".to_string());
            }
        }

        let mut out = Vec::new();
        helper(&root, &mut out);
        out.join(",")
    }

    // Deserializes your encoded data to tree.
    pub fn deserialize(&self, data: String) -> Option<Rc<RefCell<TreeNode>>> {
        let mut vals = data.split(',').collect::<Vec<_>>();
        let mut pos = 0;

        fn helper(vals: &[&str], pos: &mut usize) -> Option<Rc<RefCell<TreeNode>>> {
            if *pos >= vals.len() {
                return None;
            }
            if vals[*pos] == "null" {
                *pos += 1;
                return None;
            }

            let node = Rc::new(RefCell::new(TreeNode::new(vals[*pos].parse::<i32>().unwrap())));
            *pos += 1;
            node.borrow_mut().left = helper(vals, pos);
            node.borrow_mut().right = helper(vals, pos);
            Some(node)
        }

        helper(&vals, &mut pos)
    }
}
```

## 3. Example Test

```rust
fn main() {
    // Build this tree:
    //      1
    //     / \
    //   2   3
    //      / \
    //     4   5

    let n1 = Rc::new(RefCell::new(TreeNode::new(1)));
    let n2 = Rc::new(RefCell::new(TreeNode::new(2)));
    let n3 = Rc::new(RefCell::new(TreeNode::new(3)));
    let n4 = Rc::new(RefCell::new(TreeNode::new(4)));
    let n5 = Rc::new(RefCell::new(TreeNode::new(5)));

    n1.borrow_mut().left = Some(n2.clone());
    n1.borrow_mut().right = Some(n3.clone());
    n3.borrow_mut().left = Some(n4.clone());
    n3.borrow_mut().right = Some(n5.clone());

    let root = Some(n1);

    let codec = Codec::new();
    let ser = codec.serialize(root.clone());
    println!("Serialized: {}", ser);

    let deser = codec.deserialize(ser);
    println!("Deserialized: {:?}", deser);

    // Check that root and deser are structurally equal
    assert_eq!(root, deser);
}
```

---

**How it works:**

- **serialize**: Converts the tree to a preorder string (`"1,2,null,null,3,4,null,null,5,null,null"`).
- **deserialize**: Rebuilds the tree by walking through the value list recursively.

