    use super::*;

    #[test]
    fn test_trie_operations() {
        let mut trie = Trie::new();
        assert!(!trie.search("apple"));
        trie.insert("apple");
        assert!(trie.search("apple"));
        assert!(!trie.search("app"));
        assert!(trie.starts_with("app"));
        trie.insert("app");
        assert!(trie.search("app"));
    }
}

fn main() {
    let mut trie = Trie::new();
    trie.insert("hello");
    trie.insert("world");
    trie.insert("helium");

    println!("Search 'hello': {}", trie.search("hello")); // true
    println!("Search 'hell': {}", trie.search("hell"));   // false
    println!("Starts with 'hel': {}", trie.starts_with("hel")); // true
    println!("Starts with 'wo': {}", trie.starts_with("wo"));   // true
    println!("Search 'helium': {}", trie.search("helium")); // true
}
