This implementation computes the shortest path from a source node to all other nodes. There's also a sample usage in the `main` function.

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

// To use BinaryHeap as a min-heap, we define a struct with an Ord implementation.
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: usize,
    position: usize,
}

// Reverse ordering so that BinaryHeap pops the lowest cost first.
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice that we flip the ordering here
        other.cost.cmp(&self.cost)
            .then_with(|| self.position.cmp(&other.position))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Each edge has a destination node and a weight
#[derive(Clone, Debug)]
struct Edge {
    node: usize,
    weight: usize,
}

// Dijkstra's shortest paths from 'start' node
fn dijkstra(
    adj_list: &Vec<Vec<Edge>>,
    start: usize
) -> Vec<Option<usize>> {
    let n = adj_list.len();
    let mut dist: Vec<Option<usize>> = vec![None; n]; // None == infinity
    let mut heap = BinaryHeap::new();

    dist[start] = Some(0);
    heap.push(State { cost: 0, position: start });

    while let Some(State { cost, position }) = heap.pop() {
        // If we've already found a better path, continue
        if let Some(d) = dist[position] {
            if cost > d {
                continue;
            }
        }

        for edge in &adj_list[position] {
            let next = State {
                cost: cost + edge.weight,
                position: edge.node,
            };

            if dist[edge.node].is_none() || next.cost < dist[edge.node].unwrap() {
                dist[edge.node] = Some(next.cost);
                heap.push(next);
            }
        }
    }

    dist
}

fn main() {
    // Example graph:
    //
    // (0)--1--(1)--2--(2)
    //  |     /  |
    //  4    3   1
    //  |  /     |
    // (3)------(4)
    //      5
    //
    // Represented as adjacency list here:
    let adj_list = vec![
        vec![Edge { node: 1, weight: 1 }, Edge { node: 3, weight: 4 }],           // 0
        vec![Edge { node: 0, weight: 1 }, Edge { node: 2, weight: 2 }, Edge { node: 3, weight: 3 }, Edge { node: 4, weight: 1 }], // 1
        vec![Edge { node: 1, weight: 2 }, Edge { node: 4, weight: 5 }],           // 2
        vec![Edge { node: 0, weight: 4 }, Edge { node: 1, weight: 3 }, Edge { node: 4, weight: 5 }], // 3
        vec![Edge { node: 1, weight: 1 }, Edge { node: 2, weight: 5 }, Edge { node: 3, weight: 5 }], // 4
    ];

    let start = 0;
    let distances = dijkstra(&adj_list, start);

    println!("Shortest distances from node {}:", start);
    for (i, dist) in distances.iter().enumerate() {
        match dist {
            Some(d) => println!("  to node {}: {}", i, d),
            None => println!("  to node {}: unreachable", i),
        }
    }
}
