## Token Bucket Rate Limiter in Rust

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use std::thread;

/// A thread-safe token bucket rate limiter.
pub struct TokenBucket {
    /// Maximum number of tokens in the bucket.
    capacity: u32,
    /// Number of tokens added per second.
    refill_rate: u32,
    /// Shared state protected by a Mutex.
    state: Mutex<BucketState>,
}

struct BucketState {
    tokens: f64,
    last_refill: Instant,
}

impl TokenBucket {
    /// Creates a new TokenBucket.
    ///
    /// # Arguments
    /// * `capacity` - Maximum burst size.
    /// * `refill_rate` - Tokens per second.
    pub fn new(capacity: u32, refill_rate: u32) -> Self {
        TokenBucket {
            capacity,
            refill_rate,
            state: Mutex::new(BucketState {
                tokens: capacity as f64,
                last_refill: Instant::now(),
            }),
        }
    }

    /// Try to consume a token. Returns `true` if allowed, otherwise `false`.
    pub fn try_acquire(&self) -> bool {
        let mut state = self.state.lock().unwrap();

        // Refill tokens based on elapsed time
        let now = Instant::now();
        let elapsed = now.duration_since(state.last_refill);
        let tokens_to_add = (elapsed.as_secs_f64()) * (self.refill_rate as f64);
        state.tokens = (state.tokens + tokens_to_add).min(self.capacity as f64);
        state.last_refill = now;

        if state.tokens >= 1.0 {
            state.tokens -= 1.0;
            true
        } else {
            false
        }
    }
}

// --------------------------------------------
// EXAMPLE USAGE
// --------------------------------------------
fn main() {
    // 5 requests per second, burst capacity 10
    let rate_limiter = Arc::new(TokenBucket::new(10, 5));

    // Simulate 3 threads making requests
    let mut handles = vec![];
    for i in 0..3 {
        let limiter = Arc::clone(&rate_limiter);
        let handle = thread::spawn(move || {
            for j in 0..20 {
                if limiter.try_acquire() {
                    println!("[Thread {i}] allowed at try {j}");
                } else {
                    println!("[Thread {i}] rate-limited at try {j}");
                }
                thread::sleep(Duration::from_millis(150));
            }
        });
        handles.push(handle);
    }

    // Wait for all threads
    for handle in handles {
        handle.join().unwrap();
    }
}
```

---

## How It Works

- **Refilling tokens:** Every call to `try_acquire()` updates the bucket with tokens proportional to the elapsed time, up to the capacity.
- **Consuming a token:** Only allows the operation if there’s at least 1 token available.
- **Thread-safety:** `Mutex` on state protects concurrent access.
- **Flexible:** You can tune `capacity` (burst size) and `refill_rate` (steady rate per second).

---

## Example Output

With `capacity=10` and `refill_rate=5`, running this example you’ll see that each thread can initially burst a few times, then gets rate-limited according to the refill rate.

---

## Usage

- As a library, just use `TokenBucket::new(...)` and `.try_acquire()`.
- For async scenarios, you can adapt this to use `tokio::sync::Mutex` and yields.

