Certainly! Here is a **bounded blocking queue** implemented in Rust, using standard synchronization primitives. It is:

- **Generic** over the item type (`T`).
- **Bounded**: Has a maximum capacity.
- **Blocking**: `push` blocks if full; `pop` blocks if empty.
- **Thread-safe**: Uses `Mutex` and `Condvar`.

```rust
use std::collections::VecDeque;
use std::sync::{Mutex, Condvar, Arc};
use std::time::{Duration, Instant};

pub struct BoundedBlockingQueue<T> {
    inner: Mutex<Inner<T>>,
    not_empty: Condvar,
    not_full: Condvar,
    capacity: usize,
}

struct Inner<T> {
    queue: VecDeque<T>,
}

impl<T> BoundedBlockingQueue<T> {
    /// Create a new bounded blocking queue with specified capacity.
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0);
        BoundedBlockingQueue {
            inner: Mutex::new(Inner {
                queue: VecDeque::with_capacity(capacity),
            }),
            not_empty: Condvar::new(),
            not_full: Condvar::new(),
            capacity,
        }
    }

    /// Push an item to the queue. Blocks if the queue is full.
    pub fn push(&self, item: T) {
        let mut inner = self.inner.lock().unwrap();
        while inner.queue.len() == self.capacity {
            inner = self.not_full.wait(inner).unwrap();
        }
        inner.queue.push_back(item);
        self.not_empty.notify_one();
    }

    /// Pop an item from the queue. Blocks if the queue is empty.
    pub fn pop(&self) -> T {
        let mut inner = self.inner.lock().unwrap();
        while inner.queue.is_empty() {
            inner = self.not_empty.wait(inner).unwrap();
        }
        let item = inner.queue.pop_front().unwrap();
        self.not_full.notify_one();
        item
    }

    /// Try to push, but time out after duration. Returns Ok(()) if item added,
    /// Err(item) if timeout occurred.
    pub fn push_timeout(&self, item: T, dur: Duration) -> Result<(), T> {
        let mut inner = self.inner.lock().unwrap();
        let mut now = Instant::now();
        while inner.queue.len() == self.capacity {
            let (lock, result) = self.not_full.wait_timeout(inner, dur - now.elapsed()).unwrap();
            if result.timed_out() {
                return Err(item);
            }
            inner = lock;
            now = Instant::now();
        }
        inner.queue.push_back(item);
        self.not_empty.notify_one();
        Ok(())
    }

    /// Try to pop, but time out after duration. Returns Some(item) if received,
    /// None if timeout occurred.
    pub fn pop_timeout(&self, dur: Duration) -> Option<T> {
        let mut inner = self.inner.lock().unwrap();
        let mut now = Instant::now();
        while inner.queue.is_empty() {
            let (lock, result) = self.not_empty.wait_timeout(inner, dur - now.elapsed()).unwrap();
            if result.timed_out() {
                return None;
            }
            inner = lock;
            now = Instant::now();
        }
        let item = inner.queue.pop_front().unwrap();
        self.not_full.notify_one();
        Some(item)
    }

    /// Get current length of the queue
    pub fn len(&self) -> usize {
        let inner = self.inner.lock().unwrap();
        inner.queue.len()
    }

    /// Get capacity
    pub fn capacity(&self) -> usize {
        self.capacity
    }
}

// Example usage and simple test
#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;

    #[test]
    fn basic_blocking_queue() {
        let q = Arc::new(BoundedBlockingQueue::new(2));
        let q1 = Arc::clone(&q);
        let t = thread::spawn(move || {
            q1.push(1);
            q1.push(2);
            // Will block until a pop occurs
            q1.push(3);
        });

        thread::sleep(Duration::from_millis(100));
        assert_eq!(q.pop(), 1);
        thread::sleep(Duration::from_millis(100));
        assert_eq!(q.pop(), 2);
        thread::sleep(Duration::from_millis(100));
        assert_eq!(q.pop(), 3);

        t.join().unwrap();
    }

    #[test]
    fn push_pop_timeout() {
        let q = Arc::new(BoundedBlockingQueue::new(1));
        assert!(q.push_timeout(1, Duration::from_millis(100)).is_ok());
        // Now full, next push should fail with timeout
        assert!(q.push_timeout(2, Duration::from_millis(200)).is_err());
        // Pop should succeed
        assert_eq!(q.pop_timeout(Duration::from_millis(100)), Some(1));
        // Now empty, pop should fail with timeout
        assert_eq!(q.pop_timeout(Duration::from_millis(100)), None);
    }
}
```

---

**Usage**:  
- The queue can be shared between threads using `Arc`.
- Call `push` or `pop` to block when full/empty.
- Or use `push_timeout`/`pop_timeout` for non-infinite blocking.

