```rust
use std::io::{self, Write};
use std::iter::Peekable;
use std::str::Chars;

#[derive(Debug, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Star,
    Slash,
    LParen,
    RParen,
}

struct Lexer<'a> {
    chars: Peekable<Chars<'a>>,
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Lexer {
            chars: input.chars().peekable(),
        }
    }

    fn next_token(&mut self) -> Option<Token> {
        while let Some(&c) = self.chars.peek() {
            match c {
                ' ' | '\t' => { self.chars.next(); }
                '0'..='9' | '.' => return Some(self.lex_number()),
                '+' => { self.chars.next(); return Some(Token::Plus); }
                '-' => { self.chars.next(); return Some(Token::Minus); }
                '*' => { self.chars.next(); return Some(Token::Star); }
                '/' => { self.chars.next(); return Some(Token::Slash); }
                '(' => { self.chars.next(); return Some(Token::LParen); }
                ')' => { self.chars.next(); return Some(Token::RParen); }
                _ => {
                    self.chars.next();
                    // Ignore unknown character (could return an error)
                }
            }
        }
        None
    }

    fn lex_number(&mut self) -> Token {
        let mut number = String::new();
        let mut dot_count = 0;

        while let Some(&c) = self.chars.peek() {
            if c == '.' {
                dot_count += 1;
                if dot_count > 1 {
                    break; // Only one dot allowed
                }
                number.push(c);
                self.chars.next();
            } else if c.is_ascii_digit() {
                number.push(c);
                self.chars.next();
            } else {
                break;
            }
        }
        Token::Number(number.parse::<f64>().unwrap())
    }
}

// Recursive descent parser for:
// Expr    = Term ( ( "+" | "-" ) Term )*
// Term    = Factor ( ( "*" | "/" ) Factor )*
// Factor  = number | "(" Expr ")" | "-" Factor

struct Parser<'a> {
    tokens: Vec<Token>,
    pos: usize,
}

impl<'a> Parser<'a> {
    fn new(tokens: Vec<Token>) -> Self {
        Parser { tokens, pos: 0 }
    }

    fn parse(&mut self) -> Result<f64, String> {
        let val = self.parse_expr()?;
        if self.pos < self.tokens.len() {
            Err("Unexpected input after parsing finished.".to_string())
        } else {
            Ok(val)
        }
    }

    fn parse_expr(&mut self) -> Result<f64, String> {
        let mut lhs = self.parse_term()?;
        while self.match_token(&[Token::Plus, Token::Minus]) {
            let op = self.previous().clone();
            let rhs = self.parse_term()?;
            lhs = match op {
                Token::Plus => lhs + rhs,
                Token::Minus => lhs - rhs,
                _ => unreachable!(),
            };
        }
        Ok(lhs)
    }

    fn parse_term(&mut self) -> Result<f64, String> {
        let mut lhs = self.parse_factor()?;
        while self.match_token(&[Token::Star, Token::Slash]) {
            let op = self.previous().clone();
            let rhs = self.parse_factor()?;
            lhs = match op {
                Token::Star => lhs * rhs,
                Token::Slash => lhs / rhs,
                _ => unreachable!(),
            };
        }
        Ok(lhs)
    }

    fn parse_factor(&mut self) -> Result<f64, String> {
        if self.match_token(&[Token::Minus]) {
            // Unary minus
            let val = self.parse_factor()?;
            Ok(-val)
        } else if self.match_token(&[Token::LParen]) {
            let val = self.parse_expr()?;
            if self.match_token(&[Token::RParen]) {
                Ok(val)
            } else {
                Err("Expected ')'".to_string())
            }
        } else if self.match_token(&[Token::Number(0.0)]) {
            if let Token::Number(n) = self.previous().clone() {
                Ok(n)
            } else {
                Err("Expected number".to_string())
            }
        } else {
            Err("Unexpected token".to_string())
        }
    }

    fn match_token(&mut self, kinds: &[Token]) -> bool {
        if self.pos >= self.tokens.len() {
            return false;
        }
        for kind in kinds {
            if std::mem::discriminant(&self.tokens[self.pos]) == std::mem::discriminant(kind) {
                self.pos += 1;
                return true;
            }
        }
        false
    }
    fn previous(&self) -> &Token {
        &self.tokens[self.pos - 1]
    }
}

fn tokenize(input: &str) -> Vec<Token> {
    let mut lexer = Lexer::new(input);
    let mut tokens = vec![];
    while let Some(tok) = lexer.next_token() {
        tokens.push(tok);
    }
    tokens
}

fn main() {
    println!("Enter expression:");
    let mut input = String::new();
    io::stdout().flush().unwrap();
    io::stdin().read_line(&mut input).unwrap();
    let tokens = tokenize(&input);
    let mut parser = Parser::new(tokens);
    match parser.parse() {
        Ok(result) => println!("Result: {}", result),
        Err(e) => println!("Error: {}", e),
    }
}

```

---

**How it works:**

- **Lexer:** Converts the input string into tokens (numbers, operators, parentheses).
- **Parser:** Uses recursive descent to evaluate the expression according to operator precedence and associativity.
- **Main:** Reads an expression from the user, tokenizes, parses, and prints the result.

**Features:**
- Supports floating-point and integer numbers.
- Handles `+`, `-`, `*`, `/`, and parentheses.
- Handles unary minus (`-3 + 4`)
- Ignores whitespace.

