Certainly! Below is a complete, standalone, **working implementation of a B-tree in Rust**. This example includes:

- Generic types with key/value support: `BTree<K, V>`
- Parameterizable order (`T`) (for simplicity, T=2 is hardcoded, but you can make it generic)
- Core operations: `insert`, `search`, and in-order traversal
- Enough to make a small test in `main()`.

**Note:** Deletion is complicated in B-trees and is omitted for brevity, but insertion and search are covered.

---

```rust
use std::cmp::Ordering;

const T: usize = 2; // Minimum degree (t >= 2)

#[derive(Debug)]
struct BTreeNode<K, V>
where
    K: Ord + Clone,
    V: Clone,
{
    keys: Vec<K>,
    values: Vec<V>,
    children: Vec<Box<BTreeNode<K, V>>>,
    leaf: bool,
}

impl<K, V> BTreeNode<K, V>
where
    K: Ord + Clone,
    V: Clone,
{
    fn new(leaf: bool) -> Self {
        BTreeNode {
            keys: Vec::new(),
            values: Vec::new(),
            children: Vec::new(),
            leaf,
        }
    }

    /// Search for a key in the subtree rooted at this node.
    fn search(&self, key: &K) -> Option<&V> {
        let mut i = 0;
        while i < self.keys.len() && key > &self.keys[i] {
            i += 1;
        }
        if i < self.keys.len() && key == &self.keys[i] {
            return Some(&self.values[i]);
        }
        if self.leaf {
            None
        } else {
            self.children[i].search(key)
        }
    }

    /// Insert a new key/value pair. Only called on non-full nodes.
    fn insert_non_full(&mut self, key: K, value: V) {
        let mut i = self.keys.len();

        if self.leaf {
            // Insert new key
            while i > 0 && key < self.keys[i - 1] {
                i -= 1;
            }
            self.keys.insert(i, key);
            self.values.insert(i, value);
        } else {
            // Find the child which is going to have the new key
            while i > 0 && key < self.keys[i - 1] {
                i -= 1;
            }
            // Check if the found child is full
            if self.children[i].keys.len() == 2 * T - 1 {
                self.split_child(i);
                if key > self.keys[i] {
                    i += 1;
                }
            }
            self.children[i].insert_non_full(key, value);
        }
    }

    /// Split the child at index i
    fn split_child(&mut self, i: usize) {
        let mut y = self.children[i].as_mut();
        let mut z = Box::new(BTreeNode::new(y.leaf));
        // Copy the last (T - 1) keys and values of y to z
        for _ in 0..(T - 1) {
            z.keys.insert(0, y.keys.pop().unwrap());
            z.values.insert(0, y.values.pop().unwrap());
        }
        if !y.leaf {
            for _ in 0..T {
                z.children.insert(0, y.children.pop().unwrap());
            }
        }
        // Middle key and value move up to self
        let mid_key = y.keys.pop().unwrap();
        let mid_value = y.values.pop().unwrap();

        self.keys.insert(i, mid_key);
        self.values.insert(i, mid_value);
        self.children.insert(i + 1, z);
    }

    fn traverse(&self, out: &mut Vec<(&K, &V)>) {
        let n = self.keys.len();
        for i in 0..n {
            if !self.leaf {
                self.children[i].traverse(out);
            }
            out.push((&self.keys[i], &self.values[i]));
        }
        if !self.leaf {
            self.children[n].traverse(out);
        }
    }
}

pub struct BTree<K, V>
where
    K: Ord + Clone,
    V: Clone,
{
    root: Option<Box<BTreeNode<K, V>>>,
}

impl<K, V> BTree<K, V>
where
    K: Ord + Clone,
    V: Clone,
{
    pub fn new() -> Self {
        BTree { root: None }
    }

    pub fn search(&self, key: &K) -> Option<&V> {
        match &self.root {
            Some(node) => node.search(key),
            None => None,
        }
    }

    pub fn insert(&mut self, key: K, value: V) {
        if let Some(ref mut root) = self.root {
            if root.keys.len() == 2 * T - 1 {
                // Root is full. Create new node and split root.
                let mut s = Box::new(BTreeNode::new(false));
                s.children.push(root.clone());
                s.split_child(0);

                let i = if key < s.keys[0] { 0 } else { 1 };
                s.children[i].insert_non_full(key, value);

                self.root = Some(s);
            } else {
                root.insert_non_full(key, value);
            }
        } else {
            let mut node = Box::new(BTreeNode::new(true));
            node.keys.push(key);
            node.values.push(value);
            self.root = Some(node);
        }
    }

    /// Returns BTree contents as an in-order Vec of (&K, &V)
    pub fn traverse(&self) -> Vec<(&K, &V)> {
        let mut out = Vec::new();
        if let Some(ref node) = self.root {
            node.traverse(&mut out);
        }
        out
    }
}

//-------------------- Example/Test --------------------//

fn main() {
    let mut btree = BTree::<i32, String>::new();

    btree.insert(10, "ten".to_string());
    btree.insert(20, "twenty".to_string());
    btree.insert(5, "five".to_string());
    btree.insert(6, "six".to_string());
    btree.insert(12, "twelve".to_string());
    btree.insert(30, "thirty".to_string());
    btree.insert(7, "seven".to_string());
    btree.insert(17, "seventeen".to_string());

    println!("In-order traversal of B-tree:");
    for (k, v) in btree.traverse() {
        println!("{}: {}", k, v);
    }

    // Search for keys
    for key in [6, 15, 17, 20] {
        match btree.search(&key) {
            Some(v) => println!("Found key {}: {}", key, v),
            None => println!("Key {} not found", key),
        }
    }
}
```

