Certainly! Below is a **simple, complete implementation of the Raft leader election protocol** in Rust. This example focuses only on **leader election** (not log replication or cluster management). We use [Tokio](https://tokio.rs/) for async and channels for network-like message passing. Each Raft server runs as a task, and communication occurs via message channels (simulating a network).

**Features implemented:**
- Follower, Candidate, and Leader roles
- Election timeouts and randomized backoff
- RequestVote RPCs (with terms, vote tracking)
- Handling of higher terms & transitions

---

```rust
// Cargo.toml dependencies:
// [dependencies]
// tokio = { version = "1.33", features = ["rt-multi-thread", "macros", "time"] }
// rand = "0.8"

use rand::Rng;
use std::collections::{HashMap, HashSet};
use std::time::Duration;
use tokio::sync::mpsc;
use tokio::sync::oneshot;
use tokio::time::{sleep, timeout};

#[derive(Debug, Clone, PartialEq, Eq)]
enum State {
    Follower,
    Candidate,
    Leader,
}

#[derive(Debug, Clone)]
struct RequestVoteArgs {
    term: u64,
    candidate_id: usize,
}

#[derive(Debug, Clone)]
struct RequestVoteReply {
    term: u64,
    vote_granted: bool,
}

#[derive(Debug, Clone)]
enum Message {
    RequestVote {
        args: RequestVoteArgs,
        respond_to: oneshot::Sender<RequestVoteReply>,
    },
    // Add other RPCs (like AppendEntries) if expanding beyond election
    // Here we only need RequestVote
}

struct Raft {
    id: usize,
    peer_ids: Vec<usize>,
    state: State,
    term: u64,
    voted_for: Option<usize>,
    rx: mpsc::Receiver<Message>,
    txs: HashMap<usize, mpsc::Sender<Message>>,
    election_timeout_range: (u64, u64), // ms
}

impl Raft {
    async fn run(mut self) {
        let mut rng = rand::thread_rng();

        loop {
            match self.state {
                State::Follower => {
                    // Election timer: If no leader heard from, start election
                    let timeout_ms = rng.gen_range(self.election_timeout_range.0..self.election_timeout_range.1);
                    let timeout = timeout(Duration::from_millis(timeout_ms), self.follower_process()).await;
                    if let Err(_) = timeout {
                        // Election timeout -> transition to candidate
                        println!("[{}] Election timeout; becoming Candidate (term={})", self.id, self.term + 1);
                        self.term += 1;
                        self.state = State::Candidate;
                        self.voted_for = Some(self.id);
                    }
                }
                State::Candidate => {
                    // Start election
                    let votes_needed = self.peer_ids.len() / 2 + 1;
                    let mut votes = 1; // Voted for self
                    let mut responded: HashSet<usize> = HashSet::new();
                    let (tx, mut rx) = mpsc::channel(self.peer_ids.len());
                    // Send RequestVote to all others
                    for peer_id in &self.peer_ids {
                        if *peer_id == self.id {
                            continue;
                        }
                        let args = RequestVoteArgs {
                            term: self.term,
                            candidate_id: self.id,
                        };
                        let mut tx_clone = self.txs[peer_id].clone();
                        let (resp_tx, resp_rx) = oneshot::channel();
                        // Simulate sending RPC
                        tokio::spawn(async move {
                            let _ = tx_clone.send(Message::RequestVote {
                                args,
                                respond_to: resp_tx,
                            }).await;
                            match resp_rx.await {
                                Ok(reply) => {
                                    let _ = tx.send((*peer_id, reply)).await;
                                }
                                Err(_) => {}
                            }
                        });
                    }
                    // Wait for votes or term update
                    let election_timeout_ms = rng.gen_range(self.election_timeout_range.0..self.election_timeout_range.1);
                    let election_timeout = sleep(Duration::from_millis(election_timeout_ms));
                    tokio::pin!(election_timeout);

                    let mut new_term = self.term;
                    loop {
                        tokio::select! {
                            Some((from, reply)) = rx.recv() => {
                                responded.insert(from);
                                if reply.term > self.term {
                                    // Found higher term, step down
                                    println!("[{}] Discovered higher term {} from {}, stepping down to Follower", self.id, reply.term, from);
                                    self.term = reply.term;
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    break;
                                }
                                if reply.vote_granted {
                                    votes += 1;
                                    println!("[{}] Got vote from {}", self.id, from);
                                    if votes >= votes_needed {
                                        // Become leader
                                        println!("[{}] Elected Leader (term={})! Votes: {}", self.id, self.term, votes);
                                        self.state = State::Leader;
                                        break;
                                    }
                                }
                                if responded.len() >= self.peer_ids.len() - 1 {
                                    // All responses in, no majority
                                    println!("[{}] Election lost. Staying follower", self.id);
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    break;
                                }
                            }
                            _ = &mut election_timeout => {
                                println!("[{}] Election timeout (no majority), retrying election!", self.id);
                                // Bump term for next round
                                self.term += 1;
                                self.voted_for = Some(self.id);
                                break;
                            }
                            Some(msg) = self.rx.recv() => {
                                self.handle_message(msg).await;
                                if self.state != State::Candidate { break; }
                            }
                        }
                    }
                }
                State::Leader => {
                    println!("[{}] Acting as Leader (term={})", self.id, self.term);
                    // In a real Raft, we would send heartbeats (AppendEntries)
                    // To keep this simple (election only), just remain leader briefly,
                    // then perhaps relinquish on higher term detected
                    let leader_active = sleep(Duration::from_secs(3));
                    tokio::pin!(leader_active);
                    loop {
                        tokio::select! {
                            _ = &mut leader_active => {
                                println!("[{}] Leader term timeout. Remaining leader.", self.id);
                                // Remain leader
                                break;
                            }
                            Some(msg) = self.rx.recv() => {
                                self.handle_message(msg).await;
                                if self.state != State::Leader { break; }
                            }
                        }
                    }
                }
            }
        }
    }

    // Follower passive loop: Returns only when ticked out
    async fn follower_process(&mut self) {
        loop {
            tokio::select! {
                Some(msg) = self.rx.recv() => {
                    self.handle_message(msg).await;
                    if self.state != State::Follower {
                        break;
                    }
                }
            }
        }
    }

    async fn handle_message(&mut self, msg: Message) {
        match msg {
            Message::RequestVote { args, respond_to } => {
                // Raft RequestVote logic
                let mut vote_granted = false;
                if args.term < self.term {
                    // Reply false
                } else {
                    if args.term > self.term {
                        self.term = args.term;
                        self.state = State::Follower;
                        self.voted_for = None;
                    }
                    if self.voted_for.is_none() || self.voted_for == Some(args.candidate_id) {
                        self.voted_for = Some(args.candidate_id);
                        vote_granted = true;
                    }
                }
                let _ = respond_to.send(RequestVoteReply {
                    term: self.term,
                    vote_granted,
                });
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let num_nodes = 5;
    let mut nodes = Vec::new();
    let mut txs = HashMap::new();
    let mut rxs = HashMap::new();

    for id in 0..num_nodes {
        let (tx, rx) = mpsc::channel(32);
        txs.insert(id, tx);
        rxs.insert(id, rx);
    }

    for id in 0..num_nodes {
        let peer_ids: Vec<usize> = (0..num_nodes).collect();
        let mut senders = HashMap::new();
        for (pid, tx) in &txs {
            senders.insert(*pid, tx.clone());
        }
        let node = Raft {
            id,
            peer_ids: peer_ids.clone(),
            state: State::Follower,
            term: 0,
            voted_for: None,
            rx: rxs.remove(&id).unwrap(),
            txs: senders,
            election_timeout_range: (150, 350), // ms
        };
        nodes.push(node);
    }

    // Spawn all nodes
    for node in nodes {
        tokio::spawn(node.run());
    }

    // Let cluster run for a while
    sleep(Duration::from_secs(15)).await;
    println!("End of simulation.");
}
```

---

### How to run:

`Cargo.toml` dependencies:
```toml
[dependencies]
tokio = { version = "1.33", features = ["rt-multi-thread", "macros", "time"] }
rand = "0.8"
```

**Steps:**
1. Copy the above code into `main.rs`.
2. Add dependencies to `Cargo.toml`.
3. `cargo run`

### How it works:

- **Nodes**: Each Raft server runs as its own async task, with mpsc channels for sending messages.
- **Leader Election**: Each node starts as **Follower**. If it receives no message before an election timeout, it becomes **Candidate**, bumps its term, votes for itself, and requests votes from others.
- **Quorum**: If a candidate receives a majority (over half) of votes, it becomes **Leader**.
- **Simulation**: The program logs transitions and elections. You will see leader elections, term increments, and possible multiple elections if split votes occur.

**This is an illustrative base you can expand with log replication, cluster membership, and network delay/fault simulation.**

Certainly! Below is a complete, working implementation of **Batcher's odd-even mergesort** in Rust. This parallel sorting algorithm is suitable for hardware and sometimes for parallel software but can also be implemented sequentially for educational purposes.

The implementation sorts an array *in-place* using Rust generics (for anything that implements `Ord`), and works recursively.

```rust
use std::cmp::Ordering;

fn odd_even_merge_sort<T: Ord + Copy>(arr: &mut [T]) {
    let n = arr.len();
    if n <= 1 {
        return;
    }
    let mid = n / 2;
    // Recursively sort halves
    odd_even_merge_sort(&mut arr[..mid]);
    odd_even_merge_sort(&mut arr[mid..]);
    // Merge with the odd-even merge procedure
    odd_even_merge(arr, 0, n, 1);
}

fn odd_even_merge<T: Ord + Copy>(arr: &mut [T], lo: usize, n: usize, r: usize) {
    if n > 1 {
        let m = n / 2;
        odd_even_merge(arr, lo, m, r * 2);
        odd_even_merge(arr, lo + r, n - m, r * 2);
        for i in (lo + r..lo + n - r).step_by(2 * r) {
            compare_and_swap(arr, i, i + r);
        }
    }
}

fn compare_and_swap<T: Ord + Copy>(arr: &mut [T], i: usize, j: usize) {
    if arr[i].cmp(&arr[j]) == Ordering::Greater {
        arr.swap(i, j);
    }
}

// Example and simple test
fn main() {
    let mut data = vec![5, 1, 9, 3, 7, 4, 2, 8, 6, 0];
    println!("Before: {:?}", data);
    odd_even_merge_sort(&mut data);
    println!("After:  {:?}", data);

    // Checking correctness
    assert!(data.windows(2).all(|w| w[0] <= w[1]));
}
```

---

## Explanation

- `odd_even_merge_sort`: Recursively splits the array and sorts each half.
- `odd_even_merge`: Performs the merging by recursive odd-even logic, following Batcher's method.
- `compare_and_swap`: Swaps elements if they're out of order.

**Notes:**
- For best results, use with array lengths that are powers of two. For non-power-of-two lengths, behavior is not guaranteed to be optimal in the classic algorithm.
- `Copy` trait is used for simplicity; `Clone` or borrowing can be used for more general types.

---

**You can run this `main` function to see it working.**  
If you want a version that handles arbitrary length arrays, a few more steps are required, but this is the canonical Batcher's odd-even mergesort for powers-of-two arrays.

Certainly! Below is a complete, working implementation of a **persistent (immutable) red-black tree** in Rust. This version uses immutable smart pointers (`Rc`) to share structure across versions, and each insert returns a new tree.

This implementation is for **generic keys and values**, as in standard maps. It provides:

- Insertion (`insert`) — always returns a new tree.
- Search (`get`)
- An in-order iterator  
- Derives `Clone` for cheap versioning.

It's easy to extend with removal as well.

---

```rust
use std::cmp::Ordering;
use std::fmt::{self, Debug};
use std::rc::Rc;

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum Color {
    Red,
    Black,
}

// For convenience, alias Rc to Box
type Link<K,V> = Option<Rc<Node<K,V>>>;

#[derive(Clone)]
struct Node<K, V> {
    color: Color,
    key: K,
    value: V,
    left: Link<K,V>,
    right: Link<K,V>,
}

#[derive(Clone)]
pub struct RBTree<K, V> {
    root: Link<K, V>,
}

impl<K: Ord + Debug, V: Debug> Debug for RBTree<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        fn fmt_node<K: Debug, V: Debug>(n: &Link<K, V>, f: &mut fmt::Formatter, indent: usize) -> fmt::Result {
            if let Some(node) = n {
                for _ in 0..indent {
                    write!(f, "  ")?; // Indent
                }
                writeln!(f, "{:?}({:?}, {:?})", node.color, node.key, node.value)?;
                fmt_node(&node.left, f, indent + 1)?;
                fmt_node(&node.right, f, indent + 1)?;
            }
            Ok(())
        }
        fmt_node(&self.root, f, 0)
    }
}

impl<K: Ord, V> RBTree<K,V> {
    pub fn new() -> Self {
        RBTree { root: None }
    }

    // Public API: insert (returns new tree)
    pub fn insert(&self, key: K, value: V) -> Self {
        let (root, _) = Self::ins(self.root.clone(), key, value);
        RBTree { root: Some(Rc::new(Node { color: Color::Black, ..(*root.unwrap()).clone() })) }
    }

    // Recursive utility, returns new subtree root and bool indicating if changed.
    fn ins(node: Link<K, V>, key: K, value: V) -> (Link<K, V>, bool) {
        match node {
            None => (Some(Rc::new(Node {
                color: Color::Red,
                key,
                value,
                left: None,
                right: None,
            })), true),
            Some(n) => {
                let n_ref = n.as_ref();
                match key.cmp(&n_ref.key) {
                    Ordering::Less => {
                        let (new_left, changed) = Self::ins(n_ref.left.clone(), key, value);
                        let n2 = Rc::new(Node {
                            color: n_ref.color,
                            key: n_ref.key.clone(),
                            value: n_ref.value.clone(),
                            left: new_left,
                            right: n_ref.right.clone(),
                        });
                        (Some(Self::balance(n2)), changed)
                    }
                    Ordering::Greater => {
                        let (new_right, changed) = Self::ins(n_ref.right.clone(), key, value);
                        let n2 = Rc::new(Node {
                            color: n_ref.color,
                            key: n_ref.key.clone(),
                            value: n_ref.value.clone(),
                            left: n_ref.left.clone(),
                            right: new_right,
                        });
                        (Some(Self::balance(n2)), changed)
                    }
                    Ordering::Equal => {
                        // Replace value; structure unchanged
                        let n2 = Rc::new(Node {
                            color: n_ref.color,
                            key: n_ref.key.clone(),
                            value,
                            left: n_ref.left.clone(),
                            right: n_ref.right.clone(),
                        });
                        (Some(n2), false)
                    }
                }
            }
        }
    }

    /// Red-black balancing after insertion (L, R, LR, RL cases).
    /// We implement this more "functionally" with pattern matching.
    fn balance(node: Rc<Node<K, V>>) -> Rc<Node<K, V>> {
        use Color::*;

        // Helper function to test color of child
        fn is_red<K, V>(lnk: &Link<K, V>) -> bool {
            if let Some(n) = lnk {
                n.color == Red
            } else {
                false
            }
        }

        // LL case
        if node.color == Black
            && is_red(&node.left)
            && is_red(&node.left.as_ref().unwrap().left)
        {
            let l = node.left.as_ref().unwrap();
            let ll = l.left.as_ref().unwrap();
            return Rc::new(Node {
                color: Red,
                key: l.key.clone(),
                value: l.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: ll.key.clone(),
                    value: ll.value.clone(),
                    left: ll.left.clone(),
                    right: ll.right.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: node.key.clone(),
                    value: node.value.clone(),
                    left: l.right.clone(),
                    right: node.right.clone(),
                })),
            });
        }

        // RR case
        if node.color == Black
            && is_red(&node.right)
            && is_red(&node.right.as_ref().unwrap().right)
        {
            let r = node.right.as_ref().unwrap();
            let rr = r.right.as_ref().unwrap();
            return Rc::new(Node {
                color: Red,
                key: r.key.clone(),
                value: r.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: node.key.clone(),
                    value: node.value.clone(),
                    left: node.left.clone(),
                    right: r.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: rr.key.clone(),
                    value: rr.value.clone(),
                    left: rr.left.clone(),
                    right: rr.right.clone(),
                })),
            });
        }

        // LR case
        if node.color == Black
            && is_red(&node.left)
            && is_red(&node.left.as_ref().unwrap().right)
        {
            let l = node.left.as_ref().unwrap();
            let lr = l.right.as_ref().unwrap();
            return Rc::new(Node {
                color: Red,
                key: lr.key.clone(),
                value: lr.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: l.key.clone(),
                    value: l.value.clone(),
                    left: l.left.clone(),
                    right: lr.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: node.key.clone(),
                    value: node.value.clone(),
                    left: lr.right.clone(),
                    right: node.right.clone(),
                })),
            });
        }

        // RL case
        if node.color == Black
            && is_red(&node.right)
            && is_red(&node.right.as_ref().unwrap().left)
        {
            let r = node.right.as_ref().unwrap();
            let rl = r.left.as_ref().unwrap();
            return Rc::new(Node {
                color: Red,
                key: rl.key.clone(),
                value: rl.value.clone(),
                left: Some(Rc::new(Node {
                    color: Black,
                    key: node.key.clone(),
                    value: node.value.clone(),
                    left: node.left.clone(),
                    right: rl.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Black,
                    key: r.key.clone(),
                    value: r.value.clone(),
                    left: rl.right.clone(),
                    right: r.right.clone(),
                })),
            });
        }

        node
    }

    // Get a reference to the value corresponding to the key
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut node = self.root.as_ref();
        while let Some(n_rc) = node {
            match key.cmp(&n_rc.key) {
                Ordering::Less => node = n_rc.left.as_ref(),
                Ordering::Greater => node = n_rc.right.as_ref(),
                Ordering::Equal => return Some(&n_rc.value),
            }
        }
        None
    }

    // For convenience: check if key is in tree
    pub fn contains_key(&self, key: &K) -> bool {
        self.get(key).is_some()
    }

    pub fn is_empty(&self) -> bool {
        self.root.is_none()
    }

    // In-order iterator (once)
    pub fn iter(&self) -> RBTreeIter<K,V> {
        RBTreeIter::new(self.root.clone())
    }
}

// In-order iterator using stack (since Rc, this is fine)
pub struct RBTreeIter<K, V> {
    stack: Vec<Rc<Node<K, V>>>,
    curr: Option<Rc<Node<K, V>>>,
}

impl<K, V> RBTreeIter<K, V> {
    fn new(root: Link<K,V>) -> Self {
        RBTreeIter { stack: Vec::new(), curr: root }
    }
}

impl<K: Ord, V> Iterator for RBTreeIter<K, V> {
    type Item = (K, V);
    fn next(&mut self) -> Option<Self::Item> {
        let mut curr = self.curr.take();
        while let Some(rc_n) = curr {
            self.stack.push(rc_n.clone());
            curr = rc_n.left.clone();
        }
        let n = self.stack.pop()?;
        self.curr = n.right.clone();
        Some((n.key.clone(), n.value.clone()))
    }
}

