---

```rust
// lamport.rs

/// Lamport clock implementation for distributed events ordering.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct LamportClock {
    pub time: u64,
}

impl LamportClock {
    /// Initializes the Lamport clock.
    pub fn new() -> Self {
        LamportClock { time: 0 }
    }

    /// Called before a local event (e.g., sending a message).
    pub fn tick(&mut self) {
        self.time += 1;
    }

    /// Call this when receiving a message with timestamp `remote_time`.
    pub fn receive(&mut self, remote_time: u64) {
        self.time = std::cmp::max(self.time, remote_time) + 1;
    }

    /// Returns the current Lamport time.
    pub fn get_time(&self) -> u64 {
        self.time
    }
}

// Demonstration with 2 simulated nodes exchanging messages.
#[cfg(test)]
mod tests {
    use super::*;

    // Simulated message containing Lamport timestamp and a payload
    struct Message {
        lamport: u64,
        payload: String,
    }

    #[test]
    fn test_lamport_clock() {
        let mut node_a = LamportClock::new();
        let mut node_b = LamportClock::new();

        // Node A performs a local event
        node_a.tick();
        let msg1 = Message {
            lamport: node_a.get_time(),
            payload: "Hello from A".to_string(),
        };

        // Node B receives message from A
        node_b.receive(msg1.lamport);
        assert!(node_b.get_time() > msg1.lamport);

        // Node B performs a local event
        node_b.tick();
        let msg2 = Message {
            lamport: node_b.get_time(),
            payload: "Reply from B".to_string(),
        };

        // Node A receives message from B
        node_a.receive(msg2.lamport);

        // Now verify time ordering
        assert!(node_a.get_time() > node_b.get_time() - 1);
        assert!(node_a.get_time() >= msg1.lamport);
        assert!(node_b.get_time() >= msg2.lamport);
    }
}

fn main() {
    // Example usage:

    let mut process1 = LamportClock::new();
    let mut process2 = LamportClock::new();

    // Process 1 sends a message
    process1.tick();
    let msg_to_2 = process1.get_time();

    // Process 2 receives message, updates its clock
    process2.receive(msg_to_2);

    println!("Process 1 Lamport time: {}", process1.get_time());
    println!("Process 2 Lamport time: {}", process2.get_time());
}
```

---

**How it Works:**
- **tick()**: Call this when your process does something (e.g., sends a message).
- **receive(remote_time)**: Call this with the timestamp from a received message to update your clock.

**Usage Notes:**
- Include the local Lamport timestamp in every message payload you send.
- On receipt, call `receive()` with the remote timestamp before processing the message.

