Certainly! Below is a **complete, working implementation of a generic skip list in Rust**. This version supports `insert`, `contains`, `remove`, and basic iteration for types that implement `Ord + Clone`. The randomization uses the `rand` crate, so you'll need to add `rand = "0.8"` (or above) to your `Cargo.toml`.

---

```rust
use rand::{thread_rng, Rng};
use std::cmp::Ordering;
use std::fmt::Debug;
use std::ptr;

const MAX_LEVEL: usize = 16;
const P: f64 = 0.5;

struct Node<T> {
    value: Option<T>,
    next: Vec<*mut Node<T>>,
}

pub struct SkipList<T> {
    head: *mut Node<T>,
    level: usize,
    length: usize,
}

impl<T> Node<T> {
    fn new(value: Option<T>, level: usize) -> *mut Self {
        Box::into_raw(Box::new(Node {
            value,
            next: vec![ptr::null_mut(); level],
        }))
    }
}

impl<T: Ord + Clone + Debug> SkipList<T> {
    pub fn new() -> Self {
        let head = Node::new(None, MAX_LEVEL);
        SkipList {
            head,
            level: 1,
            length: 0,
        }
    }

    fn random_level() -> usize {
        let mut lvl = 1;
        let mut rng = thread_rng();
        while rng.gen::<f64>() < P && lvl < MAX_LEVEL {
            lvl += 1;
        }
        lvl
    }

    pub fn insert(&mut self, value: T) {
        let mut update = vec![self.head; MAX_LEVEL];
        let mut curr = self.head;

        // Find path where to insert
        unsafe {
            for i in (0..self.level).rev() {
                while !(*curr).next[i].is_null() {
                    let next = (*curr).next[i];
                    match (*next).value.as_ref().unwrap().cmp(&value) {
                        Ordering::Less => curr = next,
                        Ordering::Equal => {
                            // Replace value for set semantics
                            (*next).value = Some(value);
                            return;
                        }
                        Ordering::Greater => break,
                    }
                }
                update[i] = curr;
            }
            let new_level = Self::random_level();

            if new_level > self.level {
                for i in self.level..new_level {
                    update[i] = self.head;
                }
                self.level = new_level;
            }

            let new_node = Node::new(Some(value), new_level);

            for i in 0..new_level {
                (*new_node).next[i] = (*update[i]).next[i];
                (*update[i]).next[i] = new_node;
            }
            self.length += 1;
        }
    }

    pub fn contains(&self, value: &T) -> bool {
        unsafe {
            let mut curr = self.head;
            for i in (0..self.level).rev() {
                while !(*curr).next[i].is_null()
                    && (*(*curr).next[i])
                        .value
                        .as_ref()
                        .unwrap()
                        .cmp(value)
                        == Ordering::Less
                {
                    curr = (*curr).next[i];
                }
            }
            let curr = (*curr).next[0];
            if !curr.is_null() {
                (*curr).value.as_ref().unwrap().cmp(value) == Ordering::Equal
            } else {
                false
            }
        }
    }

    pub fn remove(&mut self, value: &T) -> bool {
        let mut update = vec![self.head; MAX_LEVEL];
        unsafe {
            let mut curr = self.head;
            for i in (0..self.level).rev() {
                while !(*curr).next[i].is_null()
                    && (*(*curr).next[i])
                        .value
                        .as_ref()
                        .unwrap()
                        .cmp(value)
                        == Ordering::Less
                {
                    curr = (*curr).next[i];
                }
                update[i] = curr;
            }
            let target = (*curr).next[0];
            if target.is_null() || (*target).value.as_ref().unwrap().cmp(value) != Ordering::Equal {
                return false;
            }
            for i in 0..self.level {
                if (*update[i]).next[i] != target {
                    break;
                }
                (*update[i]).next[i] = (*target).next[i];
            }
            while self.level > 1
                && (*self.head).next[self.level - 1].is_null()
            {
                self.level -= 1;
            }
            drop(Box::from_raw(target));
            self.length -= 1;
            true
        }
    }

    pub fn len(&self) -> usize {
        self.length
    }

    pub fn is_empty(&self) -> bool {
        self.length == 0
    }

    pub fn iter(&self) -> SkipListIter<T> {
        unsafe {
            SkipListIter {
                curr: (*self.head).next[0],
            }
        }
    }
}

impl<T> Drop for SkipList<T> {
    fn drop(&mut self) {
        unsafe {
            let mut curr = (*self.head).next[0];
            while !curr.is_null() {
                let next = (*curr).next[0];
                drop(Box::from_raw(curr));
                curr = next;
            }
            drop(Box::from_raw(self.head));
        }
    }
}

pub struct SkipListIter<T> {
    curr: *mut Node<T>,
}

impl<T: Clone> Iterator for SkipListIter<T> {
    type Item = T;
    fn next(&mut self) -> Option<Self::Item> {
        unsafe {
            if self.curr.is_null() {
                None
            } else {
                let node = &*self.curr;
                self.curr = node.next[0];
                node.value.clone()
            }
        }
    }
}

//-------------------//
// --- Example: ---  //
//-------------------//

fn main() {
    let mut sl = SkipList::<i32>::new();

    for &v in &[10, 2, 30, 15, 7] {
        sl.insert(v);
    }

    println!("SkipList contains 15?: {}", sl.contains(&15));
    println!("SkipList contains 99?: {}", sl.contains(&99));

    println!("Iterating skip list:");
    for x in sl.iter() {
        println!("{}", x);
    }

    sl.remove(&15);
    println!("After removing 15:");
    for x in sl.iter() {
        println!("{}", x);
    }

    println!("SkipList len: {}", sl.len());
}

```

