Certainly! Here is a minimal but functional quantum computing simulator in Rust, under 50 lines, that can handle basic state vector simulation for a small number of qubits. It supports single-qubit gates and a simple way to apply them.

```rust
use num_complex::Complex64;
use std::f64::consts::FRAC_1_SQRT_2;

type State = Vec<Complex64>;

fn apply_gate(state: &mut State, gate: [[Complex64; 2]; 2], qubit: usize, n: usize) {
    for i in 0..state.len() {
        if (i >> qubit) & 1 == 0 {
            let j = i | (1 << qubit);
            let a = state[i];
            let b = state[j];
            state[i] = gate[0][0] * a + gate[0][1] * b;
            state[j] = gate[1][0] * a + gate[1][1] * b;
        }
    }
}

fn main() {
    let n = 2; // number of qubits
    let mut state = vec![Complex64::new(0.0, 0.0); 1 << n];
    state[0] = Complex64::new(1.0, 0.0);

    let hadamard = [
        [Complex64::new(FRAC_1_SQRT_2, 0.0), Complex64::new(FRAC_1_SQRT_2, 0.0)],
        [Complex64::new(FRAC_1_SQRT_2, 0.0), Complex64::new(-FRAC_1_SQRT_2, 0.0)],
    ];

    apply_gate(&mut state, hadamard, 0, n);
    apply_gate(&mut state, hadamard, 1, n);
    println!("State:");
    for (i, amp) in state.iter().enumerate() {
        println!("|{:0width$b}>: {}", i, amp, width = n);
    }
}
```

